var QUESTIONS_THEORY_17 = [
{type:"mcq",diff:"easy",en:{q:"Who is considered the original creator of the Java programming language?",opts:["Dennis Ritchie","Bjarne Stroustrup","James Gosling","Guido van Rossum"],ans:2,exp:"James Gosling, along with his team at Sun Microsystems, is credited with inventing Java in 1991. The language was initially called Oak and was designed for interactive television, but was later repurposed for the World Wide Web. Sun Microsystems released the first public implementation as Java 1.0 in 1996."},hi:{q:"जावा प्रोग्रामिंग भाषा का मूल निर्माता किसे माना जाता है?",opts:["डेनिस रिची","बजार्ने स्ट्रॉस्ट्रुप","जेम्स गोस्लिंग","गुइडो वैन रोसुम"],ans:2,exp:"जेम्स गोस्लिंग और सन माइक्रोसिस्टम्स में उनकी टीम को 1991 में जावा का आविष्कार करने का श्रेय दिया जाता है। इस भाषा को शुरू में ओक (Oak) कहा जाता था और इसे इंटरैक्टिव टेलीविजन के लिए डिज़ाइन किया गया था, लेकिन बाद में इसे वर्ल्ड वाइड वेब के लिए पुन: उपयोग किया गया। सन माइक्रोसिस्टम्स ने 1996 में जावा 1.0 के रूप में पहला सार्वजनिक कार्यान्वयन जारी किया।"}},
{type:"mcq",diff:"easy",en:{q:"What was the original name of the Java programming language?",opts:["C++","Oak","Python","Ruby"],ans:1,exp:"The Java programming language was originally named Oak after an oak tree that stood outside James Gosling's office. Later, the project went by the name Green and was finally renamed Java, from Java coffee, a type of coffee from Indonesia. The name was chosen to reflect the energy and dynamic nature of the language."},hi:{q:"जावा प्रोग्रामिंग भाषा का मूल नाम क्या था?",opts:["C++","ओक (Oak)","पायथन (Python)","रूबी (Ruby)"],ans:1,exp:"जावा प्रोग्रामिंग भाषा का मूल नाम जेम्स गोस्लिंग के कार्यालय के बाहर खड़े एक ओक (Oak) के पेड़ के नाम पर रखा गया था। बाद में, प्रोजेक्ट का नाम ग्रीन रखा गया और अंततः इसका नाम बदलकर जावा कर दिया गया, जो इंडोनेशिया की एक प्रकार की कॉफी, जावा कॉफी से लिया गया था। यह नाम भाषा की ऊर्जा और गतिशील प्रकृति को दर्शाने के लिए चुना गया था।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is responsible for converting Java source code into bytecode?",opts:["JVM","JRE","Java Compiler (javac)","JIT"],ans:2,exp:"The Java Compiler (javac) reads Java source files (.java) and translates them into an intermediate, platform-independent format called bytecode (.class files). This bytecode is not native machine code, meaning it cannot be executed directly by the computer's CPU. It requires the JVM to interpret and run it."},hi:{q:"निम्नलिखित में से कौन जावा स्रोत कोड (source code) को बाइटकोड (bytecode) में परिवर्तित करने के लिए जिम्मेदार है?",opts:["JVM","JRE","जावा कंपाइलर (javac)","JIT"],ans:2,exp:"जावा कंपाइलर (javac) जावा स्रोत फ़ाइलों (.java) को पढ़ता है और उन्हें बाइटकोड (.class फ़ाइलें) नामक एक मध्यवर्ती, प्लेटफ़ॉर्म-स्वतंत्र प्रारूप में अनुवादित करता है। यह बाइटकोड मूल मशीन कोड नहीं है, जिसका अर्थ है कि इसे सीधे कंप्यूटर के CPU द्वारा निष्पादित नहीं किया जा सकता है। इसे व्याख्या (interpret) और चलाने के लिए JVM की आवश्यकता होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What does JVM stand for in the context of Java?",opts:["Java Variable Machine","Java Virtual Machine","Java Visual Machine","Java Verified Module"],ans:1,exp:"JVM stands for Java Virtual Machine. It is an abstract computing machine that enables a computer to run a Java program. When you run a Java program, the JVM is responsible for loading the bytecode, verifying it, and executing it on the underlying operating system and hardware architecture."},hi:{q:"जावा के संदर्भ में JVM का पूर्ण रूप क्या है?",opts:["जावा वेरिएबल मशीन","जावा वर्चुअल मशीन","जावा विज़ुअल मशीन","जावा वेरीफाइड मॉड्यूल"],ans:1,exp:"JVM का अर्थ जावा वर्चुअल मशीन (Java Virtual Machine) है। यह एक अमूर्त कंप्यूटिंग मशीन है जो कंप्यूटर को जावा प्रोग्राम चलाने में सक्षम बनाती है। जब आप एक जावा प्रोग्राम चलाते हैं, तो JVM बाइटकोड को लोड करने, उसे सत्यापित करने और अंतर्निहित ऑपरेटिंग सिस्टम और हार्डवेयर आर्किटेक्चर पर निष्पादित करने के लिए जिम्मेदार होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is a core principle of Java that allows it to run on different operating systems?",opts:["Write Once, Run Anywhere (WORA)","Platform Dependence","Use of Pointers","Manual Memory Management"],ans:0,exp:"'Write Once, Run Anywhere' (WORA) is the foundational principle of Java. It means that compiled Java code (bytecode) can run on all platforms that support Java without the need for recompilation. This platform independence is achieved because the JVM translates the universal bytecode into machine-specific instructions at runtime."},hi:{q:"निम्नलिखित में से कौन सा जावा का एक मुख्य सिद्धांत है जो इसे विभिन्न ऑपरेटिंग सिस्टम पर चलने की अनुमति देता है?",opts:["एक बार लिखें, कहीं भी चलाएं (WORA)","प्लेटफ़ॉर्म निर्भरता (Platform Dependence)","पॉइंटर्स का उपयोग","मैन्युअल मेमोरी प्रबंधन"],ans:0,exp:"'एक बार लिखें, कहीं भी चलाएं' (WORA) जावा का मूलभूत सिद्धांत है। इसका मतलब है कि संकलित (compiled) जावा कोड (बाइटकोड) उन सभी प्लेटफॉर्म पर चल सकता है जो जावा का समर्थन करते हैं, बिना पुनर्संकलन (recompilation) की आवश्यकता के। यह प्लेटफ़ॉर्म स्वतंत्रता इसलिए प्राप्त की जाती है क्योंकि JVM रनटाइम पर यूनिवर्सल बाइटकोड को मशीन-विशिष्ट निर्देशों में अनुवादित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the file extension of a compiled Java program?",opts:[".java",".js",".class",".txt"],ans:2,exp:"When a Java source file (.java) is successfully compiled using the javac tool, it generates one or more files with a .class extension. These .class files contain the platform-independent bytecode generated by the compiler. The Java Virtual Machine executes these .class files."},hi:{q:"संकलित (compiled) जावा प्रोग्राम का फ़ाइल एक्सटेंशन क्या होता है?",opts:[".java",".js",".class",".txt"],ans:2,exp:"जब एक जावा स्रोत फ़ाइल (.java) को javac टूल का उपयोग करके सफलतापूर्वक संकलित किया जाता है, तो यह .class एक्सटेंशन के साथ एक या अधिक फ़ाइलें उत्पन्न करता है। इन .class फ़ाइलों में कंपाइलर द्वारा उत्पन्न प्लेटफ़ॉर्म-स्वतंत्र बाइटकोड होता है। जावा वर्चुअल मशीन इन .class फ़ाइलों को निष्पादित करती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which method is the starting point for any standalone Java application?",opts:["start()","run()","init()","main()"],ans:3,exp:"The main() method is the entry point for standalone Java applications. Its exact signature must be 'public static void main(String[] args)'. When you execute a Java class, the JVM specifically looks for this method signature to start the execution flow of the program."},hi:{q:"किसी भी स्टैंडअलोन जावा एप्लिकेशन के लिए प्रारंभिक बिंदु कौन सा मेथड (method) है?",opts:["start()","run()","init()","main()"],ans:3,exp:"main() मेथड स्टैंडअलोन जावा एप्लिकेशनों के लिए प्रवेश बिंदु है। इसका सटीक सिग्नेचर 'public static void main(String[] args)' होना चाहिए। जब आप जावा क्लास निष्पादित करते हैं, तो JVM विशेष रूप से प्रोग्राम के निष्पादन प्रवाह को शुरू करने के लिए इस मेथड सिग्नेचर को खोजता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the size of an 'int' data type in Java?",opts:["2 bytes","4 bytes","8 bytes","16 bytes"],ans:1,exp:"In Java, the 'int' data type is a 32-bit (4 bytes) signed two's complement integer. Its value range lies between -2,147,483,648 and 2,147,483,647. Unlike languages like C or C++, the size of an 'int' in Java is strictly defined by the language specification and does not change across different platforms."},hi:{q:"जावा में 'int' डेटा प्रकार (data type) का आकार क्या है?",opts:["2 बाइट्स","4 बाइट्स","8 बाइट्स","16 बाइट्स"],ans:1,exp:"जावा में, 'int' डेटा प्रकार एक 32-बिट (4 बाइट्स) साइन्ड टूज़ कॉम्प्लिमेंट (two's complement) पूर्णांक है। इसका मूल्य सीमा -2,147,483,648 और 2,147,483,647 के बीच है। C या C++ जैसी भाषाओं के विपरीत, जावा में 'int' का आकार भाषा विनिर्देश द्वारा कड़ाई से परिभाषित किया गया है और यह विभिन्न प्लेटफार्मों पर नहीं बदलता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the size of a 'char' data type in Java?",opts:["1 byte","2 bytes","4 bytes","8 bytes"],ans:1,exp:"In Java, the 'char' data type is a single 16-bit (2 bytes) Unicode character. It has a minimum value of '\\u0000' (or 0) and a maximum value of '\\uffff' (or 65,535). Java uses 2 bytes to support the internationalization of characters (Unicode system) rather than the 1-byte ASCII system."},hi:{q:"जावा में 'char' डेटा प्रकार का आकार क्या है?",opts:["1 बाइट","2 बाइट्स","4 बाइट्स","8 बाइट्स"],ans:1,exp:"जावा में, 'char' डेटा प्रकार एक 16-बिट (2 बाइट्स) यूनिकोड वर्ण है। इसका न्यूनतम मान '\\u0000' (या 0) और अधिकतम मान '\\uffff' (या 65,535) है। 1-बाइट ASCII सिस्टम के बजाय वर्णों (Unicode सिस्टम) के अंतर्राष्ट्रीयकरण का समर्थन करने के लिए जावा 2 बाइट्स का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is not a primitive data type in Java?",opts:["boolean","byte","String","float"],ans:2,exp:"In Java, 'String' is not a primitive data type; it is an object representing a sequence of characters and is defined by the java.lang.String class. Primitive data types in Java include byte, short, int, long, float, double, char, and boolean, which store simple values directly in memory."},hi:{q:"निम्नलिखित में से कौन जावा में एक आदिम डेटा प्रकार (primitive data type) नहीं है?",opts:["boolean","byte","String","float"],ans:2,exp:"जावा में, 'String' एक आदिम (primitive) डेटा प्रकार नहीं है; यह एक ऑब्जेक्ट है जो वर्णों के अनुक्रम का प्रतिनिधित्व करता है और java.lang.String क्लास द्वारा परिभाषित किया गया है। जावा में प्रिमिटिव डेटा प्रकारों में बाइट, शॉर्ट, इंट, लॉन्ग, फ्लोट, डबल, चार और बूलियन शामिल हैं, जो सीधे मेमोरी में सरल मान संग्रहीत करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the default value of a boolean variable declared as a class member?",opts:["true","false","0","null"],ans:1,exp:"In Java, if a boolean variable is declared as a field (class member) but not explicitly initialized, the compiler assigns it a default value of 'false'. Local variables, however, must be explicitly initialized before use, as they do not receive default values."},hi:{q:"क्लास मेंबर के रूप में घोषित बूलियन (boolean) वेरिएबल का डिफ़ॉल्ट मान क्या होता है?",opts:["true","false","0","null"],ans:1,exp:"जावा में, यदि किसी बूलियन चर (variable) को एक फ़ील्ड (क्लास सदस्य) के रूप में घोषित किया जाता है, लेकिन स्पष्ट रूप से प्रारंभ नहीं किया जाता है, तो कंपाइलर इसे 'false' का डिफ़ॉल्ट मान प्रदान करता है। हालाँकि, स्थानीय चर (local variables) का उपयोग करने से पहले उन्हें स्पष्ट रूप से प्रारंभ किया जाना चाहिए, क्योंकि उन्हें डिफ़ॉल्ट मान नहीं मिलते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which command is used to run a compiled Java class named 'Test'?",opts:["javac Test","java Test","run Test","execute Test"],ans:1,exp:"The 'java' command is used to launch a Java application. It starts the Java Runtime Environment (JRE), loads the specified class ('Test'), and executes its main() method. The 'javac' command is used for compiling the source code, not executing it."},hi:{q:"'Test' नामक संकलित जावा क्लास को चलाने के लिए किस कमांड का उपयोग किया जाता है?",opts:["javac Test","java Test","run Test","execute Test"],ans:1,exp:"'java' कमांड का उपयोग जावा एप्लिकेशन लॉन्च करने के लिए किया जाता है। यह जावा रनटाइम एनवायरनमेंट (JRE) को शुरू करता है, निर्दिष्ट क्लास ('Test') को लोड करता है, और इसके main() मेथड को निष्पादित करता है। 'javac' कमांड का उपयोग सोर्स कोड को संकलित करने के लिए किया जाता है, न कि इसे निष्पादित करने के लिए।"}},
{type:"mcq",diff:"easy",en:{q:"What does JRE stand for?",opts:["Java Runtime Engine","Java Runtime Environment","Java Reading Environment","Java Regular Execution"],ans:1,exp:"JRE stands for Java Runtime Environment. It is a software package that provides the class libraries, the Java Virtual Machine (JVM), and other components required to run applications written in Java. It does not contain development tools like compilers or debuggers."},hi:{q:"JRE का पूर्ण रूप क्या है?",opts:["जावा रनटाइम इंजन","जावा रनटाइम एनवायरनमेंट","जावा रीडिंग एनवायरनमेंट","जावा रेगुलर एग्जीक्यूशन"],ans:1,exp:"JRE का अर्थ जावा रनटाइम एनवायरनमेंट (Java Runtime Environment) है। यह एक सॉफ़्टवेयर पैकेज है जो क्लास लाइब्रेरी, जावा वर्चुअल मशीन (JVM) और जावा में लिखे गए एप्लिकेशन को चलाने के लिए आवश्यक अन्य घटक प्रदान करता है। इसमें कंपाइलर या डीबगर जैसे विकास उपकरण (development tools) शामिल नहीं हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which JDK tool is used to compile Java source code?",opts:["javadoc","javap","javac","java"],ans:2,exp:"The 'javac' tool is the primary Java compiler included in the Java Development Kit (JDK). It reads class and interface definitions written in the Java programming language from .java files and compiles them into bytecode, storing the result in .class files."},hi:{q:"जावा स्रोत कोड (source code) को संकलित करने के लिए किस JDK टूल का उपयोग किया जाता है?",opts:["javadoc","javap","javac","java"],ans:2,exp:"'javac' टूल जावा डेवलपमेंट किट (JDK) में शामिल प्राथमिक जावा कंपाइलर है। यह .java फ़ाइलों से जावा प्रोग्रामिंग भाषा में लिखे गए क्लास और इंटरफ़ेस परिभाषाओं को पढ़ता है और उन्हें बाइटकोड में संकलित करता है, परिणाम को .class फ़ाइलों में संग्रहीत करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which operator is used to perform logical AND in Java?",opts:["&","&&","|","||"],ans:1,exp:"In Java, the '&&' operator represents the logical AND operation. It is a short-circuit operator, meaning if the left-hand operand evaluates to false, the right-hand operand is not evaluated at all because the entire expression is guaranteed to be false. The single '&' is a bitwise AND operator."},hi:{q:"जावा में लॉजिकल AND ऑपरेशन करने के लिए किस ऑपरेटर का उपयोग किया जाता है?",opts:["&","&&","|","||"],ans:1,exp:"जावा में, '&&' ऑपरेटर लॉजिकल AND ऑपरेशन का प्रतिनिधित्व करता है। यह एक शॉर्ट-सर्किट ऑपरेटर है, जिसका अर्थ है कि यदि बायां ऑपरेंड false है, तो दायां ऑपरेंड का मूल्यांकन बिल्कुल नहीं किया जाता है क्योंकि संपूर्ण अभिव्यक्ति के false होने की गारंटी है। सिंगल '&' एक बिटवाइज़ AND ऑपरेटर है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an incorrect identifier in Java?",opts:["myVariable","1stVariable","_myVariable","$myVariable"],ans:1,exp:"In Java, an identifier (variable name, method name, class name, etc.) must begin with a letter, a currency character ($), or an underscore (_). It cannot begin with a digit. Therefore, '1stVariable' is an illegal identifier and will cause a compilation error."},hi:{q:"जावा में निम्नलिखित में से कौन सा एक गलत आइडेंटिफ़ायर (identifier) है?",opts:["myVariable","1stVariable","_myVariable","$myVariable"],ans:1,exp:"जावा में, एक आइडेंटिफ़ायर (वेरिएबल का नाम, मेथड का नाम, क्लास का नाम, आदि) एक अक्षर, एक मुद्रा वर्ण ($), या एक अंडरस्कोर (_) से शुरू होना चाहिए। यह किसी अंक (digit) से शुरू नहीं हो सकता है। इसलिए, '1stVariable' एक अवैध आइडेंटिफ़ायर है और संकलन त्रुटि (compilation error) का कारण बनेगा।"}},
{type:"mcq",diff:"easy",en:{q:"Which statement prints text to the console in Java?",opts:["print()","console.log()","System.out.println()","echo()"],ans:2,exp:"The 'System.out.println()' statement is used in Java to print the argument passed to it along with a new line on the standard output stream (usually the console). 'System' is a built-in class, 'out' is a static member representing the output stream, and 'println' is the method."},hi:{q:"जावा में कौन सा स्टेटमेंट कंसोल पर टेक्स्ट प्रिंट करता है?",opts:["print()","console.log()","System.out.println()","echo()"],ans:2,exp:"जावा में 'System.out.println()' स्टेटमेंट का उपयोग मानक आउटपुट स्ट्रीम (आमतौर पर कंसोल) पर एक नई लाइन के साथ पारित तर्क को प्रिंट करने के लिए किया जाता है। 'System' एक अंतर्निहित क्लास है, 'out' एक स्टैटिक सदस्य है जो आउटपुट स्ट्रीम का प्रतिनिधित्व करता है, और 'println' मेथड है।"}},
{type:"mcq",diff:"easy",en:{q:"How do you write a single-line comment in Java?",opts:["/* comment */","// comment","# comment","&lt;!-- comment --&gt;"],ans:1,exp:"In Java, a single-line comment begins with two forward slashes (//). The compiler ignores everything from the // to the end of the line. Multi-line comments are written using /* ... */, similar to C and C++ programming languages."},hi:{q:"आप जावा में सिंगल-लाइन कमेंट (single-line comment) कैसे लिखते हैं?",opts:["/* comment */","// comment","# comment","&lt;!-- comment --&gt;"],ans:1,exp:"जावा में, एक सिंगल-लाइन कमेंट दो फॉरवर्ड स्लैश (//) से शुरू होता है। कंपाइलर // से लेकर लाइन के अंत तक सब कुछ अनदेखा कर देता है। C और C++ प्रोग्रामिंग भाषाओं के समान, मल्टी-लाइन कमेंट /* ... */ का उपयोग करके लिखे जाते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which keyword is used to declare a constant in Java?",opts:["const","constant","final","static"],ans:2,exp:"The 'final' keyword is used in Java to declare a constant. When a variable is declared as final, its value cannot be modified once it has been initialized. It is standard practice to write final variable names in uppercase letters. The 'const' keyword is reserved but not used in Java."},hi:{q:"जावा में स्थिरांक (constant) घोषित करने के लिए किस कीवर्ड का उपयोग किया जाता है?",opts:["const","constant","final","static"],ans:2,exp:"जावा में स्थिरांक घोषित करने के लिए 'final' कीवर्ड का उपयोग किया जाता है। जब किसी वेरिएबल को फाइनल घोषित किया जाता है, तो इसके प्रारंभ (initialized) होने के बाद इसका मान बदला नहीं जा सकता है। अंतिम चर नामों को अपरकेस अक्षरों में लिखना मानक अभ्यास है। 'const' कीवर्ड आरक्षित है लेकिन जावा में इसका उपयोग नहीं किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which operator is used to compare two values for equality in Java?",opts:["=","==","===","!="],ans:1,exp:"The '==' operator is a relational operator used to compare two values for equality. It returns true if both operands are equal, and false otherwise. The single '=' operator is an assignment operator used to assign a value to a variable. '!=' represents inequality."},hi:{q:"जावा में समानता (equality) के लिए दो मानों की तुलना करने के लिए किस ऑपरेटर का उपयोग किया जाता है?",opts:["=","==","===","!="],ans:1,exp:"'==' ऑपरेटर एक रिलेशनल ऑपरेटर है जिसका उपयोग समानता के लिए दो मानों की तुलना करने के लिए किया जाता है। यह सत्य (true) लौटाता है यदि दोनों ऑपरेंड समान हैं, और अन्यथा असत्य (false) लौटाता है। सिंगल '=' ऑपरेटर एक असाइनमेंट ऑपरेटर है जिसका उपयोग किसी वेरिएबल को मान असाइन करने के लिए किया जाता है। '!=' असमानता का प्रतिनिधित्व करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a block of code that executes repeatedly as long as a condition is true?",opts:["A class","A loop","A method","An array"],ans:1,exp:"A loop is a control flow statement that allows a block of code to be executed repeatedly based on a given boolean condition. Common loop structures in Java include the 'for' loop, 'while' loop, and 'do-while' loop, which help in reducing code redundancy."},hi:{q:"कोड का वह ब्लॉक क्या है जो तब तक बार-बार निष्पादित होता है जब तक कोई शर्त सत्य (true) होती है?",opts:["एक क्लास (class)","एक लूप (loop)","एक मेथड (method)","एक ऐरे (array)"],ans:1,exp:"एक लूप एक नियंत्रण प्रवाह (control flow) स्टेटमेंट है जो दिए गए बूलियन स्थिति के आधार पर कोड के एक ब्लॉक को बार-बार निष्पादित करने की अनुमति देता है। जावा में सामान्य लूप संरचनाओं में 'for' लूप, 'while' लूप और 'do-while' लूप शामिल हैं, जो कोड अतिरेक (redundancy) को कम करने में मदद करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which primitive data type is used to store decimal numbers like 3.14?",opts:["int","char","double","boolean"],ans:2,exp:"The 'double' (and 'float') data type is used to store floating-point numbers, which include fractions or decimal points like 3.14. 'double' provides 64-bit precision and is the default type for decimal literals in Java, whereas 'float' provides 32-bit precision."},hi:{q:"3.14 जैसे दशमलव संख्याओं को संग्रहीत करने के लिए किस प्रिमिटिव डेटा प्रकार का उपयोग किया जाता है?",opts:["int","char","double","boolean"],ans:2,exp:"'double' (और 'float') डेटा प्रकार का उपयोग फ़्लोटिंग-पॉइंट संख्याओं को संग्रहीत करने के लिए किया जाता है, जिसमें 3.14 जैसे अंश या दशमलव बिंदु शामिल हैं। 'double' 64-बिट सटीकता प्रदान करता है और जावा में दशमलव लिटरल्स के लिए डिफ़ॉल्ट प्रकार है, जबकि 'float' 32-बिट सटीकता प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an Access Modifier in Java?",opts:["public","static","void","class"],ans:0,exp:"'public' is an access modifier in Java. Access modifiers specify the visibility or accessibility of a class, field, method, or constructor. The 'public' modifier means that the member is accessible from any other class globally. Other modifiers include private, protected, and default."},hi:{q:"निम्नलिखित में से कौन जावा में एक एक्सेस मॉडिफायर (Access Modifier) है?",opts:["public","static","void","class"],ans:0,exp:"'public' जावा में एक एक्सेस मॉडिफायर है। एक्सेस मॉडिफायर किसी क्लास, फील्ड, मेथड या कंस्ट्रक्टर की दृश्यता या पहुंच निर्दिष्ट करते हैं। 'पब्लिक' मॉडिफायर का मतलब है कि सदस्य को वैश्विक स्तर पर किसी भी अन्य क्लास से एक्सेस किया जा सकता है। अन्य संशोधक (modifiers) में प्राइवेट, प्रोटेक्टेड और डिफ़ॉल्ट शामिल हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does OOP stand for?",opts:["Object Oriented Programming","Object Ordered Programming","Oriented Object Protocol","Overloading Object Programming"],ans:0,exp:"OOP stands for Object-Oriented Programming. It is a programming paradigm based on the concept of 'objects', which can contain data in the form of fields (attributes) and code in the form of procedures (methods). Java is a strictly object-oriented language."},hi:{q:"OOP का पूर्ण रूप क्या है?",opts:["ऑब्जेक्ट ओरिएंटेड प्रोग्रामिंग (Object Oriented Programming)","ऑब्जेक्ट ऑर्डर्ड प्रोग्रामिंग","ओरिएंटेड ऑब्जेक्ट प्रोटोकॉल","ओवरलोडिंग ऑब्जेक्ट प्रोग्रामिंग"],ans:0,exp:"OOP का अर्थ ऑब्जेक्ट-ओरिएंटेड प्रोग्रामिंग (Object-Oriented Programming) है। यह 'ऑब्जेक्ट्स' की अवधारणा पर आधारित एक प्रोग्रामिंग प्रतिमान है, जिसमें फ़ील्ड (विशेषताओं) के रूप में डेटा और प्रक्रियाओं (मेथड्स) के रूप में कोड हो सकता है। जावा एक सख्ती से ऑब्जेक्ट-ओरिएंटेड भाषा है।"}},
{type:"mcq",diff:"easy",en:{q:"Which statement evaluates a condition and executes a block of code if the condition is true?",opts:["switch","for","if","continue"],ans:2,exp:"The 'if' statement is the most basic control flow statement. It evaluates a boolean expression and executes the associated block of code only if the condition is true. It can optionally be followed by an 'else' block which executes if the condition is false."},hi:{q:"कौन सा स्टेटमेंट किसी स्थिति का मूल्यांकन करता है और यदि स्थिति सत्य है तो कोड के एक ब्लॉक को निष्पादित करता है?",opts:["switch","for","if","continue"],ans:2,exp:"'if' स्टेटमेंट सबसे बुनियादी कंट्रोल फ्लो स्टेटमेंट है। यह एक बूलियन अभिव्यक्ति का मूल्यांकन करता है और संबंधित कोड ब्लॉक को केवल तभी निष्पादित करता है जब स्थिति सत्य (true) हो। वैकल्पिक रूप से इसके बाद एक 'else' ब्लॉक हो सकता है जो स्थिति के गलत होने पर निष्पादित होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the keyword 'void' mean in a method declaration?",opts:["The method returns an integer","The method returns no value","The method takes no parameters","The method is public"],ans:1,exp:"The 'void' keyword in a method signature indicates that the method does not return any value to the caller. It simply performs its operations and terminates. If a method does return a value, the data type of the return value must replace 'void'."},hi:{q:"मेथड डिक्लेरेशन में 'void' कीवर्ड का क्या अर्थ है?",opts:["मेथड एक पूर्णांक (integer) लौटाता है","मेथड कोई मान नहीं लौटाता है (returns no value)","मेथड कोई पैरामीटर नहीं लेता है","मेथड सार्वजनिक (public) है"],ans:1,exp:"मेथड सिग्नेचर में 'void' कीवर्ड इंगित करता है कि मेथड कॉलर को कोई मान नहीं लौटाता है। यह बस अपने संचालन करता है और समाप्त होता है। यदि कोई मेथड एक मान लौटाता है, तो वापसी मान (return value) के डेटा प्रकार को 'void' की जगह लेना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"How are multiple statements separated in Java?",opts:["By a comma (,)","By a colon (:)","By a semicolon (;)","By a period (.)"],ans:2,exp:"In Java, every individual statement must be terminated with a semicolon (;). The semicolon tells the Java compiler where a specific statement ends and the next one begins, acting as a crucial part of the language's syntax and structure."},hi:{q:"जावा में कई स्टेटमेंट्स को कैसे अलग किया जाता है?",opts:["अल्पविराम (,) द्वारा","कोलन (:) द्वारा","अर्धविराम (;) द्वारा","अवधि (.) द्वारा"],ans:2,exp:"जावा में, प्रत्येक व्यक्तिगत स्टेटमेंट को अर्धविराम (semicolon ;) के साथ समाप्त किया जाना चाहिए। अर्धविराम जावा कंपाइलर को बताता है कि एक विशिष्ट स्टेटमेंट कहाँ समाप्त होता है और अगला कहाँ से शुरू होता है, जो भाषा के सिंटैक्स और संरचना के एक महत्वपूर्ण भाग के रूप में कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following creates a block of code in Java?",opts:["Parentheses ()","Square brackets []","Curly braces {}","Angle brackets <>"],ans:2,exp:"Curly braces {} are used to group multiple statements into a single block of code. These blocks are commonly used to define the body of classes, methods, and control flow statements like loops and conditional branches, establishing their scope."},hi:{q:"निम्नलिखित में से कौन जावा में कोड का एक ब्लॉक बनाता है?",opts:["कोष्ठक ()","वर्गाकार कोष्ठक []","घुंघराले कोष्ठक (Curly braces {})","कोण कोष्ठक <>"],ans:2,exp:"घुंघराले कोष्ठक (Curly braces {}) का उपयोग कई स्टेटमेंट्स को कोड के एक ब्लॉक में समूहित करने के लिए किया जाता है। इन ब्लॉकों का उपयोग आमतौर पर क्लास, मेथड और कंट्रोल फ्लो स्टेटमेंट्स जैसे लूप और कंडीशनल ब्रांच के बॉडी को परिभाषित करने के लिए किया जाता है, जो उनके दायरे (scope) को स्थापित करते हैं।"}},
{type:"tf",diff:"easy",en:{q:"Java supports the use of pointers natively like C/C++.",opts:["True","False"],ans:1,exp:"False. Java deliberately removes native support for pointers to enhance security and robustness. Memory management and object referencing are handled implicitly by the JVM, preventing common vulnerabilities associated with manual pointer manipulation such as memory leaks or segmentation faults."},hi:{q:"जावा C/C++ की तरह मूल रूप से पॉइंटर्स के उपयोग का समर्थन करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। जावा सुरक्षा और मजबूती बढ़ाने के लिए जानबूझकर पॉइंटर्स के लिए देशी (native) समर्थन को हटा देता है। मेमोरी प्रबंधन और ऑब्जेक्ट रेफरेंसिंग को JVM द्वारा स्पष्ट रूप से नियंत्रित किया जाता है, जिससे मेमोरी लीक या सेगमेंटेशन दोष जैसे मैनुअल पॉइंटर हेरफेर से जुड़ी सामान्य कमजोरियों को रोका जा सकता है।"}},
{type:"tf",diff:"easy",en:{q:"The default value of an uninitialized int instance variable in Java is 0.",opts:["True","False"],ans:0,exp:"True. When instance variables (fields of a class) are declared but not explicitly initialized, the compiler automatically assigns them a default value. For numeric types like byte, short, int, and long, this default value is exactly 0."},hi:{q:"जावा में एक अनइनिशियलाइज्ड int इंस्टेंस वेरिएबल का डिफ़ॉल्ट मान 0 होता है।",opts:["सही","गलत"],ans:0,exp:"सही। जब इंस्टेंस चर (क्लास के फ़ील्ड) घोषित किए जाते हैं लेकिन स्पष्ट रूप से प्रारंभ नहीं किए जाते हैं, तो कंपाइलर स्वचालित रूप से उन्हें एक डिफ़ॉल्ट मान प्रदान करता है। संख्यात्मक प्रकार जैसे बाइट, शॉर्ट, इंट और लॉन्ग के लिए, यह डिफ़ॉल्ट मान ठीक 0 होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which looping construct is guaranteed to execute its block of code at least once?",opts:["for loop","while loop","do-while loop","foreach loop"],ans:2,exp:"The 'do-while' loop evaluates its boolean condition at the bottom of the loop, after the code block has executed. Therefore, regardless of whether the condition is initially true or false, the code inside the 'do' block will run exactly once before the test occurs."},hi:{q:"कौन सा लूपिंग कंस्ट्रक्ट कम से कम एक बार अपने कोड के ब्लॉक को निष्पादित करने की गारंटी देता है?",opts:["for लूप","while लूप","do-while लूप","foreach लूप"],ans:2,exp:"'do-while' लूप कोड ब्लॉक निष्पादित होने के बाद, लूप के नीचे अपनी बूलियन स्थिति का मूल्यांकन करता है। इसलिए, इस बात की परवाह किए बिना कि स्थिति शुरू में सही है या गलत, परीक्षण होने से पहले 'do' ब्लॉक के अंदर का कोड ठीक एक बार चलेगा।"}},
{type:"mcq",diff:"medium",en:{q:"What is the index of the first element in a Java array?",opts:["1","0","-1","Length of the array"],ans:1,exp:"Arrays in Java are zero-indexed, meaning the first element is accessed using the index 0. If an array has 'N' elements, the valid index range is strictly from 0 to N-1. Attempting to access an index outside this range throws an ArrayIndexOutOfBoundsException."},hi:{q:"जावा ऐरे (array) में पहले तत्व (element) का इंडेक्स क्या होता है?",opts:["1","0","-1","ऐरे की लंबाई"],ans:1,exp:"जावा में ऐरे ज़ीरो-इंडेक्स्ड (zero-indexed) होते हैं, जिसका अर्थ है कि पहले तत्व को इंडेक्स 0 का उपयोग करके एक्सेस किया जाता है। यदि एक ऐरे में 'N' तत्व हैं, तो वैध इंडेक्स सीमा कड़ाई से 0 से N-1 तक है। इस सीमा के बाहर किसी इंडेक्स तक पहुंचने का प्रयास करने पर ArrayIndexOutOfBoundsException आता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyword is used to allocate memory for a newly created object in Java?",opts:["create","allocate","new","init"],ans:2,exp:"The 'new' keyword is used to instantiate a class by dynamically allocating memory for a new object on the heap at runtime. It is followed by a call to a constructor, which initializes the newly created object before returning its reference."},hi:{q:"जावा में नव निर्मित ऑब्जेक्ट के लिए मेमोरी आवंटित करने के लिए किस कीवर्ड का उपयोग किया जाता है?",opts:["create","allocate","new","init"],ans:2,exp:"'new' कीवर्ड का उपयोग रनटाइम पर हीप (heap) पर एक नए ऑब्जेक्ट के लिए गतिशील रूप से मेमोरी आवंटित करके क्लास को इंस्टेंटियेट करने के लिए किया जाता है। इसके बाद एक कंस्ट्रक्टर को कॉल किया जाता है, जो अपना संदर्भ (reference) वापस करने से पहले नव निर्मित ऑब्जेक्ट को इनिशियलाइज़ करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What defines a 'Class' in Object-Oriented Programming?",opts:["A specific memory address","A blueprint or template for creating objects","A variable that holds multiple values","A built-in data type"],ans:1,exp:"A Class acts as a logical blueprint, template, or prototype from which individual objects are created. It defines a new data type describing the state (instance variables/fields) and behavior (methods) that the objects created from it will possess."},hi:{q:"ऑब्जेक्ट-ओरिएंटेड प्रोग्रामिंग में 'क्लास' (Class) को क्या परिभाषित करता है?",opts:["एक विशिष्ट मेमोरी एड्रेस","ऑब्जेक्ट्स बनाने के लिए एक ब्लूप्रिंट या टेम्पलेट","एक चर जो कई मान रखता है","एक अंतर्निहित डेटा प्रकार"],ans:1,exp:"क्लास एक तार्किक ब्लूप्रिंट, टेम्पलेट या प्रोटोटाइप के रूप में कार्य करता है जिससे व्यक्तिगत ऑब्जेक्ट बनाए जाते हैं। यह उस स्थिति (इंस्टेंस वेरिएबल्स/फ़ील्ड्स) और व्यवहार (मेथड्स) का वर्णन करने वाले एक नए डेटा प्रकार को परिभाषित करता है जो इससे बनाए गए ऑब्जेक्ट्स के पास होगा।"}},
{type:"mcq",diff:"medium",en:{q:"What is an 'Object' in Java?",opts:["An instance of a class","A primitive data type","A method","A compiler error"],ans:0,exp:"An object is a physical or logical entity that is an instance of a class. It occupies space in memory (heap) and consists of a specific state (field values) and behaviors (methods defined by its class). Objects communicate with each other by invoking methods."},hi:{q:"जावा में 'ऑब्जेक्ट' (Object) क्या है?",opts:["क्लास का एक उदाहरण (instance)","एक प्रिमिटिव डेटा प्रकार","एक मेथड","एक कंपाइलर त्रुटि"],ans:0,exp:"ऑब्जेक्ट एक भौतिक या तार्किक इकाई है जो किसी क्लास का एक उदाहरण (instance) है। यह मेमोरी (हीप) में जगह घेरता है और इसमें एक विशिष्ट स्थिति (फ़ील्ड मान) और व्यवहार (इसके क्लास द्वारा परिभाषित मेथड) शामिल होते हैं। ऑब्जेक्ट मेथड को लागू करके एक दूसरे के साथ संवाद करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which special method is invoked automatically when an object is created?",opts:["main()","init()","A constructor","finalize()"],ans:2,exp:"A constructor is a special block of code that resembles a method and is invoked automatically when an instance of an object is created using the 'new' keyword. Its primary purpose is to initialize the state of the new object. It must have the exact same name as the class."},hi:{q:"जब कोई ऑब्जेक्ट बनाया जाता है तो कौन सा विशेष मेथड स्वचालित रूप से लागू होता है?",opts:["main()","init()","एक कंस्ट्रक्टर (A constructor)","finalize()"],ans:2,exp:"कंस्ट्रक्टर कोड का एक विशेष ब्लॉक है जो एक मेथड जैसा दिखता है और 'new' कीवर्ड का उपयोग करके ऑब्जेक्ट का एक उदाहरण (instance) बनाए जाने पर स्वचालित रूप से लागू होता है। इसका प्राथमिक उद्देश्य नए ऑब्जेक्ट की स्थिति को प्रारंभ करना है। इसका नाम क्लास के नाम के बिल्कुल समान होना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyword is utilized to establish inheritance, allowing one class to acquire the properties of another?",opts:["implements","inherits","extends","super"],ans:2,exp:"The 'extends' keyword is used in a class declaration to indicate that the new class is derived from an existing base class. This establishes an IS-A relationship, allowing the child class (subclass) to inherit the non-private fields and methods of the parent class (superclass)."},hi:{q:"एक क्लास को दूसरे के गुणों को प्राप्त करने की अनुमति देने वाले इनहेरिटेंस (inheritance) को स्थापित करने के लिए किस कीवर्ड का उपयोग किया जाता है?",opts:["implements","inherits","extends","super"],ans:2,exp:"'extends' कीवर्ड का उपयोग क्लास डिक्लेरेशन में यह इंगित करने के लिए किया जाता है कि नई क्लास मौजूदा बेस क्लास से ली गई है। यह IS-A संबंध स्थापित करता है, जिससे चाइल्ड क्लास (उपवर्ग) को पैरेंट क्लास (सुपरक्लास) के गैर-निजी क्षेत्रों और विधियों को प्राप्त करने की अनुमति मिलती है।"}},
{type:"mcq",diff:"medium",en:{q:"In a non-static method, what does the 'this' keyword refer to?",opts:["The parent class","The current object instance","The main method","The compiler"],ans:1,exp:"The 'this' keyword is a reference variable in Java that specifically points to the current object invoking the method or constructor. It is primarily used to resolve scope ambiguity when class fields and method parameters share the exact same names."},hi:{q:"नॉन-स्टेटिक मेथड में, 'this' कीवर्ड किसको संदर्भित करता है?",opts:["पैरेंट क्लास को","वर्तमान ऑब्जेक्ट इंस्टेंस को","मेन मेथड को","कंपाइलर को"],ans:1,exp:"'this' कीवर्ड जावा में एक रेफरेंस वेरिएबल है जो विशेष रूप से मेथड या कंस्ट्रक्टर को लागू करने वाले वर्तमान ऑब्जेक्ट को इंगित करता है। इसका उपयोग मुख्य रूप से स्कोप अस्पष्टता को हल करने के लिए किया जाता है जब क्लास फ़ील्ड और मेथड पैरामीटर समान नाम साझा करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"How do you find the total number of elements present in a Java array named 'myArray'?",opts:["myArray.length()","myArray.size","myArray.length","myArray.getSize()"],ans:2,exp:"In Java, arrays have a built-in, final public property named 'length' that explicitly stores the capacity (number of elements) the array was instantiated to hold. Unlike Strings, it is accessed as a property (myArray.length), not as a method call with parentheses."},hi:{q:"आप 'myArray' नामक जावा ऐरे (array) में मौजूद तत्वों (elements) की कुल संख्या कैसे ज्ञात करते हैं?",opts:["myArray.length()","myArray.size","myArray.length","myArray.getSize()"],ans:2,exp:"जावा में, ऐरे में 'length' नामक एक अंतर्निहित (built-in), अंतिम सार्वजनिक संपत्ति (property) होती है जो स्पष्ट रूप से उस क्षमता (तत्वों की संख्या) को संग्रहीत करती है जिसे रखने के लिए ऐरे को इंस्टेंटियेट किया गया था। स्ट्रिंग्स के विपरीत, इसे एक संपत्ति (myArray.length) के रूप में एक्सेस किया जाता है, न कि कोष्ठक के साथ मेथड कॉल के रूप में।"}},
{type:"mcq",diff:"medium",en:{q:"Which statement is used to immediately terminate the execution of a loop or switch block?",opts:["continue","break","return","exit"],ans:1,exp:"The 'break' statement alters control flow. When executed inside a loop (for, while, do-while) or a switch statement, it immediately terminates the innermost enclosing block. Execution resumes at the very next statement following the terminated block."},hi:{q:"किसी लूप या स्विच ब्लॉक के निष्पादन को तुरंत समाप्त करने के लिए किस स्टेटमेंट का उपयोग किया जाता है?",opts:["continue","break","return","exit"],ans:1,exp:"'break' स्टेटमेंट नियंत्रण प्रवाह (control flow) को बदल देता है। जब एक लूप (for, while, do-while) या स्विच स्टेटमेंट के अंदर निष्पादित किया जाता है, तो यह तुरंत सबसे भीतरी संलग्न ब्लॉक को समाप्त कर देता है। निष्पादन समाप्त ब्लॉक के ठीक बाद वाले अगले स्टेटमेंट पर फिर से शुरू होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which statement forces a loop to skip the remainder of its current iteration and immediately re-evaluate its condition?",opts:["break","next","pass","continue"],ans:3,exp:"The 'continue' statement is used within looping constructs to bypass the remaining code in the current iteration. It forces an immediate jump to the next iteration of the loop, skipping any subsequent statements within the loop's body for that specific cycle."},hi:{q:"कौन सा स्टेटमेंट लूप को उसके वर्तमान इटरेशन (iteration) के शेष भाग को छोड़ने और तुरंत अपनी स्थिति का पुनर्मूल्यांकन (re-evaluate) करने के लिए बाध्य करता है?",opts:["break","next","pass","continue"],ans:3,exp:"लूपिंग कंस्ट्रक्ट के भीतर वर्तमान इटरेशन में शेष कोड को बायपास करने के लिए 'continue' स्टेटमेंट का उपयोग किया जाता है। यह लूप के अगले इटरेशन पर तत्काल कूदने (jump) के लिए बाध्य करता है, उस विशिष्ट चक्र के लिए लूप के मुख्य भाग के भीतर किसी भी बाद के स्टेटमेंट्स को छोड़ देता है।"}},
{type:"mcq",diff:"medium",en:{q:"In a 'switch' statement, which block executes if no matching 'case' value is found?",opts:["The first case","The break statement","The default block","The program crashes"],ans:2,exp:"The 'default' label is an optional component of a switch statement. It specifies the block of code to execute if none of the explicit 'case' values evaluate to a match with the switch expression. It behaves similarly to the 'else' block in an if-else chain."},hi:{q:"'switch' स्टेटमेंट में, यदि कोई मिलान 'case' मान नहीं मिलता है, तो कौन सा ब्लॉक निष्पादित होता है?",opts:["पहला case","break स्टेटमेंट","डिफ़ॉल्ट (default) ब्लॉक","प्रोग्राम क्रैश हो जाता है"],ans:2,exp:"'default' लेबल स्विच स्टेटमेंट का एक वैकल्पिक घटक है। यह निष्पादित करने के लिए कोड के ब्लॉक को निर्दिष्ट करता है यदि कोई भी स्पष्ट 'case' मान स्विच अभिव्यक्ति के साथ मेल नहीं खाता है। यह एक if-else श्रृंखला में 'else' ब्लॉक के समान व्यवहार करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What mechanism does Java use to automatically reclaim memory allocated to objects that are no longer referenced?",opts:["Memory Leaker","Destructor","Garbage Collection","Manual Deallocation"],ans:2,exp:"Garbage Collection is Java's autonomous memory management process. A daemon thread continuously runs in the background of the JVM, identifying and deleting objects that are unreachable (no longer possess any active references) to free up heap memory space."},hi:{q:"जावा उन ऑब्जेक्ट्स को आवंटित मेमोरी को स्वचालित रूप से पुनः प्राप्त करने (reclaim) के लिए किस तंत्र का उपयोग करता है जिनका अब संदर्भ नहीं है?",opts:["मेमोरी लीकर","डिस्ट्रक्टर","कचरा संग्रहण (Garbage Collection)","मैन्युअल डिएलोकेशन"],ans:2,exp:"कचरा संग्रहण (Garbage Collection) जावा की स्वायत्त मेमोरी प्रबंधन प्रक्रिया है। एक डेमॉन थ्रेड लगातार JVM की पृष्ठभूमि में चलता है, जो हीप मेमोरी स्पेस को खाली करने के लिए उन ऑब्जेक्ट्स की पहचान करता है और उन्हें हटा देता है जो अप्राप्य हैं (जिनके पास कोई सक्रिय संदर्भ नहीं है)।"}},
{type:"mcq",diff:"medium",en:{q:"Which component strictly defines a method's signature in Java?",opts:["Return type and method name","Method name and parameter list","Access modifier and parameter list","Return type, method name, and access modifier"],ans:1,exp:"In Java, a method signature strictly comprises the method's name and its parameter list (the number, type, and order of parameters). It specifically does not include the method's return type, access modifier, or the exceptions it might throw."},hi:{q:"कौन सा घटक जावा में किसी मेथड के सिग्नेचर (method signature) को कड़ाई से परिभाषित करता है?",opts:["रिटर्न टाइप और मेथड का नाम","मेथड का नाम और पैरामीटर सूची (parameter list)","एक्सेस मॉडिफायर और पैरामीटर सूची","रिटर्न टाइप, मेथड का नाम और एक्सेस मॉडिफायर"],ans:1,exp:"जावा में, एक मेथड सिग्नेचर में कड़ाई से मेथड का नाम और उसकी पैरामीटर सूची (पैरामीटर की संख्या, प्रकार और क्रम) शामिल होती है। इसमें विशेष रूप से मेथड का रिटर्न टाइप, एक्सेस मॉडिफायर, या उसके द्वारा फेंके जाने वाले अपवाद (exceptions) शामिल नहीं हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which access modifier ensures a member is accessible only within the exact same class where it is declared?",opts:["public","protected","default","private"],ans:3,exp:"The 'private' access modifier represents the most restrictive level of access in Java. Methods, variables, and constructors declared as private are strictly encapsulated and cannot be accessed or viewed by any other class, even within the same package or by subclasses."},hi:{q:"कौन सा एक्सेस मॉडिफायर यह सुनिश्चित करता है कि कोई सदस्य केवल उसी क्लास के भीतर सुलभ (accessible) है जहां उसे घोषित किया गया है?",opts:["public","protected","default","private"],ans:3,exp:"'private' एक्सेस मॉडिफायर जावा में एक्सेस के सबसे प्रतिबंधात्मक स्तर का प्रतिनिधित्व करता है। निजी (private) के रूप में घोषित मेथड्स, वेरिएबल्स और कंस्ट्रक्टर्स को सख्ती से एनकैप्सुलेट (encapsulated) किया जाता है और किसी भी अन्य क्लास द्वारा एक्सेस या देखा नहीं जा सकता है, यहां तक कि उसी पैकेज के भीतर या उपवर्गों (subclasses) द्वारा भी।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary purpose of a 'Package' in Java?",opts:["To execute the code faster","To group related classes and interfaces to prevent naming conflicts and organize code","To encrypt the source code","To define a new primitive data type"],ans:1,exp:"A Java package acts as a namespace that logically groups related classes, interfaces, and sub-packages. It prevents naming collisions (allowing two classes with the same name to exist in different packages) and provides access protection based on package-private visibility rules."},hi:{q:"जावा में 'पैकेज' (Package) का प्राथमिक उद्देश्य क्या है?",opts:["कोड को तेजी से निष्पादित करने के लिए","नामकरण विवादों को रोकने और कोड को व्यवस्थित करने के लिए संबंधित क्लास और इंटरफेस को समूहित करना","सोर्स कोड को एन्क्रिप्ट करने के लिए","एक नया प्रिमिटिव डेटा प्रकार परिभाषित करने के लिए"],ans:1,exp:"जावा पैकेज एक नेमस्पेस (namespace) के रूप में कार्य करता है जो तार्किक रूप से संबंधित क्लास, इंटरफेस और उप-पैकेज को समूहित करता है। यह नामकरण टकराव को रोकता है (समान नाम वाले दो क्लासों को अलग-अलग पैकेजों में मौजूद होने की अनुमति देता है) और पैकेज-प्राइवेट दृश्यता नियमों के आधार पर एक्सेस सुरक्षा प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which operator acts as a compact, shorthand alternative to a simple if-else statement?",opts:["Scope resolution operator (::)","Ternary conditional operator (?:)","Logical AND operator (&&)","Instanceof operator"],ans:1,exp:"The ternary conditional operator (?:) evaluates a boolean condition and executes one of two expressions. Its syntax is `condition ? exprIfTrue : exprIfFalse`. It is a highly compact, inline replacement for assigning variables based on a simple if-else decision structure."},hi:{q:"कौन सा ऑपरेटर एक साधारण if-else स्टेटमेंट के कॉम्पैक्ट, आशुलिपि (shorthand) विकल्प के रूप में कार्य करता है?",opts:["स्कोप रिज़ॉल्यूशन ऑपरेटर (::)","टर्नरी कंडीशनल ऑपरेटर (?:)","लॉजिकल AND ऑपरेटर (&&)","Instanceof ऑपरेटर"],ans:1,exp:"टर्नरी कंडीशनल ऑपरेटर (?:) एक बूलियन स्थिति का मूल्यांकन करता है और दो अभिव्यक्तियों में से एक को निष्पादित करता है। इसका सिंटैक्स `condition ? exprIfTrue : exprIfFalse` है। यह एक साधारण if-else निर्णय संरचना के आधार पर चर निर्दिष्ट करने के लिए एक अत्यधिक कॉम्पैक्ट, इनलाइन प्रतिस्थापन है।"}},
{type:"mcq",diff:"medium",en:{q:"Which built-in class serves as the ultimate superclass (root) for all classes automatically in Java?",opts:["java.lang.System","java.lang.Class","java.lang.String","java.lang.Object"],ans:3,exp:"The `java.lang.Object` class is the root of the class hierarchy in Java. Every class explicitly or implicitly inherits from it. Therefore, a reference variable of type Object can hold a reference to any object, and it provides inherited methods like `toString()`, `equals()`, and `hashCode()`."},hi:{q:"कौन सा अंतर्निहित (built-in) क्लास स्वचालित रूप से जावा में सभी क्लासों के लिए अंतिम सुपरक्लास (रूट) के रूप में कार्य करता है?",opts:["java.lang.System","java.lang.Class","java.lang.String","java.lang.Object"],ans:3,exp:"`java.lang.Object` क्लास जावा में क्लास पदानुक्रम (hierarchy) का मूल (root) है। प्रत्येक क्लास स्पष्ट या अंतर्निहित रूप से इसे इनहेरिट करता है। इसलिए, ऑब्जेक्ट प्रकार का एक संदर्भ चर (reference variable) किसी भी ऑब्जेक्ट का संदर्भ रख सकता है, और यह `toString()`, `equals()`, और `hashCode()` जैसे विरासत में मिले तरीके (methods) प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What error occurs if you try to access the 5th element of an array initialized to hold only 3 elements?",opts:["Compilation Error","NullPointerException","ArrayIndexOutOfBoundsException","Memory Limit Exceeded"],ans:2,exp:"Attempting to access an index that falls outside the legally allocated bounds of a specific array (e.g., negative index, or an index greater than or equal to the array's length) causes the JVM to throw a runtime `ArrayIndexOutOfBoundsException`."},hi:{q:"यदि आप केवल 3 तत्वों को रखने के लिए प्रारंभ किए गए (initialized) ऐरे (array) के 5वें तत्व तक पहुँचने का प्रयास करते हैं तो कौन सी त्रुटि (error) होती है?",opts:["कंपाइलेशन एरर","NullPointerException","ArrayIndexOutOfBoundsException","मेमोरी लिमिट एक्सीडेड"],ans:2,exp:"किसी ऐसे इंडेक्स तक पहुंचने का प्रयास जो किसी विशिष्ट ऐरे की कानूनी रूप से आवंटित सीमा के बाहर आता है (जैसे, नकारात्मक इंडेक्स, या ऐरे की लंबाई के बराबर या उससे अधिक इंडेक्स) JVM को रनटाइम पर `ArrayIndexOutOfBoundsException` फेंकने का कारण बनता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which Object-Oriented principle specifically refers to bundling data fields and the methods operating on them into a single secure unit?",opts:["Inheritance","Polymorphism","Abstraction","Encapsulation"],ans:3,exp:"Encapsulation is the OOP principle of wrapping data (variables) and code acting on the data (methods) together as a single autonomous unit. In practice, this is achieved by declaring class variables as private and providing public getter and setter methods to control access."},hi:{q:"कौन सा ऑब्जेक्ट-ओरिएंटेड सिद्धांत विशेष रूप से डेटा फ़ील्ड और उन पर काम करने वाले तरीकों (methods) को एक सुरक्षित इकाई में बंडल करने को संदर्भित करता है?",opts:["इनहेरिटेंस (Inheritance)","पॉलीमॉर्फिज्म (Polymorphism)","एब्स्ट्रेक्शन (Abstraction)","एनकैप्सुलेशन (Encapsulation)"],ans:3,exp:"एनकैप्सुलेशन (Encapsulation) डेटा (चर) और डेटा पर कार्य करने वाले कोड (विधियों) को एक स्वायत्त इकाई (autonomous unit) के रूप में एक साथ लपेटने का OOP सिद्धांत है। व्यवहार में, यह क्लास वेरिएबल्स को निजी (private) घोषित करके और एक्सेस को नियंत्रित करने के लिए सार्वजनिक गेट्टर (getter) और सेटर (setter) मेथड्स प्रदान करके प्राप्त किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"In array declaration, which syntax creates a continuous block of memory for 5 integer variables?",opts:["int[] arr = new int[5];","int arr = new int[5];","int[] arr = 5;","array arr = int[5];"],ans:0,exp:"The syntax `int[] arr = new int[5];` correctly declares a reference variable named 'arr' of type integer array. The `new int[5]` portion dynamically allocates contiguous memory on the heap capable of storing exactly 5 separate 32-bit integer values, initialized to 0."},hi:{q:"ऐरे डिक्लेरेशन में, कौन सा सिंटैक्स 5 पूर्णांक चर (integer variables) के लिए मेमोरी का एक सतत ब्लॉक (continuous block) बनाता है?",opts:["int[] arr = new int[5];","int arr = new int[5];","int[] arr = 5;","array arr = int[5];"],ans:0,exp:"सिंटैक्स `int[] arr = new int[5];` सही ढंग से 'arr' नामक एक संदर्भ चर घोषित करता है जो पूर्णांक ऐरे प्रकार का है। `new int[5]` भाग हीप (heap) पर गतिशील रूप से सन्निहित मेमोरी आवंटित करता है जो 0 पर प्रारंभ किए गए ठीक 5 अलग 32-बिट पूर्णांक मानों को संग्रहीत करने में सक्षम है।"}},
{type:"mcq",diff:"medium",en:{q:"What differentiates a constructor from a standard method?",opts:["A constructor has the exact same name as the class and completely lacks a return type.","A constructor must always return an object.","A constructor is called manually by the programmer.","A constructor can only be declared private."],ans:0,exp:"A constructor possesses two strict defining rules separating it from standard methods: it must have the exact same name as its encapsulating class, and it absolutely must not have an explicit return type (not even `void`). It is implicitly invoked by the `new` keyword."},hi:{q:"एक कंस्ट्रक्टर एक मानक मेथड (standard method) से कैसे अलग होता है?",opts:["एक कंस्ट्रक्टर का नाम बिल्कुल क्लास के समान होता है और इसमें रिटर्न टाइप का पूरी तरह से अभाव होता है।","एक कंस्ट्रक्टर को हमेशा एक ऑब्जेक्ट वापस (return) करना चाहिए।","एक कंस्ट्रक्टर को प्रोग्रामर द्वारा मैन्युअल रूप से कॉल किया जाता है।","एक कंस्ट्रक्टर को केवल निजी (private) घोषित किया जा सकता है।"],ans:0,exp:"एक कंस्ट्रक्टर के दो सख्त परिभाषित नियम होते हैं जो इसे मानक विधियों से अलग करते हैं: इसका नाम बिल्कुल इसके एनकैप्सुलेटिंग क्लास के समान होना चाहिए, और इसमें स्पष्ट रूप से कोई रिटर्न प्रकार (यहां तक कि `void` भी नहीं) नहीं होना चाहिए। इसे 'new' कीवर्ड द्वारा अंतर्निहित रूप से लागू किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What specifically happens when a local variable shares the identical name as a class instance variable?",opts:["Compilation Error occurs immediately.","The instance variable entirely hides the local variable.","The local variable shadows the instance variable within its scope.","The JVM crashes at runtime."],ans:2,exp:"If a local variable inside a method has the exact same name as an instance variable of the class, the local variable takes precedence within its block. This phenomenon is called 'shadowing'. To explicitly reference the hidden instance variable, the `this` keyword must be utilized."},hi:{q:"विशेष रूप से क्या होता है जब कोई स्थानीय चर (local variable) क्लास इंस्टेंस चर के समान नाम साझा करता है?",opts:["कंपाइलेशन एरर तुरंत होता है।","इंस्टेंस वेरिएबल स्थानीय वेरिएबल को पूरी तरह से छिपा देता है।","स्थानीय चर अपने दायरे (scope) के भीतर इंस्टेंस चर को छायांकित (shadow) करता है।","रनटाइम पर JVM क्रैश हो जाता है।"],ans:2,exp:"यदि किसी मेथड के अंदर एक स्थानीय चर का नाम क्लास के इंस्टेंस चर के बिल्कुल समान है, तो स्थानीय चर अपने ब्लॉक के भीतर प्राथमिकता लेता है। इस घटना को 'शैडोइंग' कहा जाता है। छिपे हुए इंस्टेंस वेरिएबल को स्पष्ट रूप से संदर्भित करने के लिए, 'this' कीवर्ड का उपयोग किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"What will be the output of `System.out.println(\"Java\" + 1 + 2);`?",opts:["Java3","Java12","Error","3Java"],ans:1,exp:"The Java expression is evaluated strictly from left to right. First, the string 'Java' is concatenated with the integer '1', resulting in the string 'Java1'. Then, 'Java1' is concatenated with '2', producing the final string output 'Java12'. To get 'Java3', parentheses are required: `\"Java\" + (1 + 2)`."},hi:{q:"`System.out.println(\"Java\" + 1 + 2);` का आउटपुट क्या होगा?",opts:["Java3","Java12","एरर (Error)","3Java"],ans:1,exp:"जावा अभिव्यक्ति का मूल्यांकन कड़ाई से बाएं से दाएं किया जाता है। सबसे पहले, स्ट्रिंग 'Java' को पूर्णांक '1' के साथ जोड़ा जाता है, जिसके परिणामस्वरूप स्ट्रिंग 'Java1' प्राप्त होता है। फिर, 'Java1' को '2' के साथ जोड़ा जाता है, जिससे अंतिम स्ट्रिंग आउटपुट 'Java12' उत्पन्न होता है। 'Java3' प्राप्त करने के लिए, कोष्ठक की आवश्यकता होती है: `\"Java\" + (1 + 2)`।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following creates an array of Strings properly?",opts:["String args = new String[];","String[] args = new String[10];","String array args = new String;","String[10] args;"],ans:1,exp:"To dynamically instantiate an array of objects, the exact size must be declared. `String[] args = new String[10];` correctly declares a reference variable 'args' of type String array and allocates space for 10 String references on the heap, each initialized to `null`."},hi:{q:"निम्नलिखित में से कौन सा स्ट्रिंग्स (Strings) का एक ऐरे (array) ठीक से बनाता है?",opts:["String args = new String[];","String[] args = new String[10];","String array args = new String;","String[10] args;"],ans:1,exp:"ऑब्जेक्ट्स के एक ऐरे को गतिशील रूप से इंस्टेंटियेट करने के लिए, सटीक आकार घोषित किया जाना चाहिए। `String[] args = new String[10];` स्ट्रिंग ऐरे प्रकार के एक संदर्भ चर 'args' को सही ढंग से घोषित करता है और हीप (heap) पर 10 स्ट्रिंग संदर्भों के लिए स्थान आवंटित करता है, जो प्रत्येक `null` पर प्रारंभ होता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the `return` statement do?",opts:["It starts a method.","It exits from the current method and optionally passes back a value.","It breaks a loop.","It throws an exception."],ans:1,exp:"The `return` statement explicitly alters control flow, immediately exiting the currently executing method. If the method signature specifies a non-void return type, the `return` statement must evaluate and strictly pass back a compatible value to the calling function."},hi:{q:"`return` स्टेटमेंट क्या करता है?",opts:["यह एक मेथड शुरू करता है।","यह वर्तमान मेथड से बाहर निकलता है और वैकल्पिक रूप से एक मान वापस पास करता है।","यह एक लूप को तोड़ता है।","यह एक अपवाद (exception) फेंकता है।"],ans:1,exp:"`return` स्टेटमेंट स्पष्ट रूप से नियंत्रण प्रवाह को बदल देता है, वर्तमान में निष्पादित मेथड से तुरंत बाहर निकल जाता है। यदि मेथड सिग्नेचर एक गैर-शून्य (non-void) रिटर्न प्रकार निर्दिष्ट करता है, तो `return` स्टेटमेंट को मूल्यांकन करना चाहिए और कॉलिंग फ़ंक्शन को एक संगत मान (compatible value) को सख्ती से वापस करना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Which access modifier makes variables invisible to subclasses residing in different packages?",opts:["public","protected","private","default (package-private)"],ans:3,exp:"A variable or method declared without any explicit access modifier has 'default' (package-private) access. This dictates that the member is exclusively accessible to classes located within the exact same package. Subclasses situated in completely different packages cannot access it."},hi:{q:"कौन सा एक्सेस मॉडिफायर विभिन्न पैकेजों में रहने वाले उपवर्गों (subclasses) के लिए चर (variables) को अदृश्य बना देता है?",opts:["public","protected","private","default (पैकेज-प्राइवेट)"],ans:3,exp:"बिना किसी स्पष्ट एक्सेस मॉडिफायर के घोषित वेरिएबल या मेथड में 'डिफ़ॉल्ट' (पैकेज-प्राइवेट) एक्सेस होता है। यह तय करता है कि सदस्य विशेष रूप से उसी सटीक पैकेज के भीतर स्थित क्लासों के लिए सुलभ है। पूरी तरह से अलग-अलग पैकेजों में स्थित उपवर्ग इसे एक्सेस नहीं कर सकते हैं।"}},
{type:"tf",diff:"medium",en:{q:"In Java, a single subclass can simultaneously inherit directly from multiple parent classes using the `extends` keyword.",opts:["True","False"],ans:1,exp:"False. Java strictly forbids multiple inheritance for classes to prevent ambiguity issues, such as the infamous 'Diamond Problem'. A class can extend one and only one superclass. However, multiple inheritance is safely supported through the implementation of interfaces."},hi:{q:"जावा में, एक एकल उपवर्ग (subclass) `extends` कीवर्ड का उपयोग करके एक साथ कई पैरेंट क्लासों (parent classes) से सीधे इनहेरिट कर सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। जावा अस्पष्टता की समस्याओं को रोकने के लिए क्लासों के लिए एकाधिक विरासत (multiple inheritance) को सख्ती से मना करता है, जैसे कि कुख्यात 'डायमंड प्रॉब्लम'। एक क्लास केवल और केवल एक सुपरक्लास का विस्तार (extend) कर सकता है। हालाँकि, इंटरफेस के कार्यान्वयन के माध्यम से बहु विरासत सुरक्षित रूप से समर्थित है।"}},
{type:"tf",diff:"medium",en:{q:"Constructors can have a return type strictly limited to `void`.",opts:["True","False"],ans:1,exp:"False. Constructors fundamentally cannot possess any return type declaration whatsoever, not even `void`. If you write `public void MyClass()`, the compiler will simply treat it as a standard method that coincidentally shares the class name, entirely stripping it of its constructor properties."},hi:{q:"कंस्ट्रक्टर्स के पास एक रिटर्न टाइप हो सकता है जो सख्ती से `void` तक सीमित होता है।",opts:["सही","गलत"],ans:1,exp:"गलत। कंस्ट्रक्टर्स के पास मौलिक रूप से किसी भी प्रकार की वापसी घोषणा (return type declaration) नहीं हो सकती है, यहाँ तक कि `void` भी नहीं। यदि आप `public void MyClass()` लिखते हैं, तो कंपाइलर इसे केवल एक मानक मेथड (standard method) मानेगा जो संयोग से क्लास नाम साझा करता है, इसे पूरी तरह से इसके कंस्ट्रक्टर गुणों से अलग कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"What defines 'Method Overloading' in Java?",opts:["Having methods with the same name and identical parameter lists in different classes.","Having multiple methods with the exact same name but differing parameter lists within the same class.","Overriding a method inherited from a superclass.","A method that calls itself recursively."],ans:1,exp:"Method Overloading is a compile-time polymorphism feature where a single class houses multiple methods sharing the exact same name. The compiler differentiates them strictly by examining their signatures: the number, type, or specific sequence of the parameters passed."},hi:{q:"जावा में 'मेथड ओवरलोडिंग' (Method Overloading) को क्या परिभाषित करता है?",opts:["विभिन्न क्लासों में समान नाम और समान पैरामीटर सूची वाले मेथड होना।","एक ही क्लास के भीतर बिल्कुल एक ही नाम लेकिन अलग-अलग पैरामीटर सूची (parameter lists) वाले कई मेथड होना।","सुपरक्लास से विरासत में मिले मेथड को ओवरराइड करना।","एक मेथड जो खुद को पुनरावर्ती (recursively) रूप से कॉल करता है।"],ans:1,exp:"मेथड ओवरलोडिंग एक संकलन-समय बहुरूपता (compile-time polymorphism) विशेषता है जहां एक एकल क्लास में बिल्कुल एक ही नाम साझा करने वाले कई मेथड होते हैं। कंपाइलर उनके हस्ताक्षर की जांच करके कड़ाई से उन्हें अलग करता है: पारित मापदंडों की संख्या, प्रकार, या विशिष्ट अनुक्रम।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically dictates 'Method Overriding'?",opts:["Creating methods with completely different names in child classes.","A subclass providing a highly specific implementation for a method already defined in its parent class, matching the exact name and parameter signature.","Changing the return type of a method in the same class.","Hiding a variable belonging to the parent class."],ans:1,exp:"Method Overriding is a mechanism of runtime polymorphism. It occurs when a subclass explicitly provides its own implementation for a non-static method already established by its superclass. The subclass method must strictly match the parent's method name, parameters, and return type."},hi:{q:"विशेष रूप से 'मेथड ओवरराइडिंग' (Method Overriding) क्या तय करता है?",opts:["चाइल्ड क्लास में पूरी तरह से अलग नाम वाले मेथड बनाना।","एक उपवर्ग (subclass) अपने मूल वर्ग (parent class) में पहले से परिभाषित मेथड के लिए एक अत्यधिक विशिष्ट कार्यान्वयन प्रदान करता है, जो सटीक नाम और पैरामीटर हस्ताक्षर से मेल खाता है।","उसी क्लास में किसी मेथड का रिटर्न टाइप बदलना।","पैरेंट क्लास से संबंधित वेरिएबल को छिपाना।"],ans:1,exp:"मेथड ओवरराइडिंग रनटाइम पॉलीमॉर्फिज्म का एक तंत्र है। यह तब होता है जब कोई उपवर्ग स्पष्ट रूप से किसी गैर-स्थिर मेथड के लिए अपना कार्यान्वयन प्रदान करता है जो पहले से ही इसके सुपरक्लास द्वारा स्थापित है। उपवर्ग मेथड को मूल वर्ग के मेथड के नाम, पैरामीटर और वापसी प्रकार से सख्ती से मेल खाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"What does the `super` keyword strictly reference?",opts:["The highest class in the hierarchy.","The object of the currently executing subclass.","The immediate parent class instance variable or method.","A static variable shared across all objects."],ans:2,exp:"The `super` reference variable operates explicitly within subclasses. It targets the immediate parent class (superclass) object. Developers use `super` primarily to invoke overridden parent methods, access hidden parent fields, or execute a specific constructor belonging to the parent class."},hi:{q:"`super` कीवर्ड कड़ाई से किसको संदर्भित (reference) करता है?",opts:["पदानुक्रम (hierarchy) में सबसे ऊपर के क्लास को।","वर्तमान में निष्पादित उपवर्ग (subclass) की वस्तु (object) को।","तत्काल पैरेंट क्लास इंस्टेंस वेरिएबल या मेथड को।","सभी ऑब्जेक्ट्स में साझा किया गया एक स्थिर (static) वेरिएबल।"],ans:2,exp:"`super` रेफरेंस वेरिएबल उपवर्गों (subclasses) के भीतर स्पष्ट रूप से काम करता है। यह तत्काल पैरेंट क्लास (सुपरक्लास) ऑब्जेक्ट को लक्षित करता है। डेवलपर्स मुख्य रूप से ओवरराइड किए गए पैरेंट मेथड्स को लागू करने, छिपे हुए पैरेंट फ़ील्ड तक पहुंचने या पैरेंट क्लास से संबंधित विशिष्ट कंस्ट्रक्टर को निष्पादित करने के लिए `super` का उपयोग करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is the consequence of declaring a method with the `static` keyword?",opts:["It cannot be accessed by any other class.","It belongs universally to the class itself rather than to individual object instances.","It absolutely must return an integer value.","It can only be executed once during the program lifecycle."],ans:1,exp:"The `static` keyword binds a member exclusively to the class. A static method or variable exists as a single entity shared across all object instances. Therefore, it can be executed directly using the class name without demanding the prior creation of a specific object instance."},hi:{q:"किसी मेथड को `static` कीवर्ड के साथ घोषित करने का क्या परिणाम होता है?",opts:["इसे किसी अन्य क्लास द्वारा एक्सेस नहीं किया जा सकता है।","यह व्यक्तिगत ऑब्जेक्ट उदाहरणों (instances) के बजाय सार्वभौमिक रूप से स्वयं क्लास से संबंधित है।","इसे निश्चित रूप से एक पूर्णांक (integer) मान वापस करना चाहिए।","इसे प्रोग्राम जीवनचक्र के दौरान केवल एक बार निष्पादित किया जा सकता है।"],ans:1,exp:"`static` कीवर्ड किसी सदस्य को विशेष रूप से क्लास से बांधता है। एक स्थिर (static) मेथड या चर एक एकल इकाई के रूप में मौजूद है जो सभी ऑब्जेक्ट उदाहरणों में साझा किया जाता है। इसलिए, किसी विशिष्ट ऑब्जेक्ट इंस्टेंस के पूर्व निर्माण की मांग किए बिना इसे सीधे क्लास के नाम का उपयोग करके निष्पादित किया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"Can a static method access non-static variables directly?",opts:["Yes, but only if they are public.","Yes, without any restrictions.","No, static methods fundamentally cannot directly access non-static instance variables or methods.","Only within the main method."],ans:2,exp:"Static methods lack an implicit `this` reference because they are not tied to any specific object instance. Consequently, a static method cannot directly access non-static fields or invoke non-static methods within the same class unless it explicitly creates an object instance to operate upon."},hi:{q:"क्या एक स्थिर मेथड (static method) गैर-स्थिर चर (non-static variables) तक सीधे पहुंच सकता है?",opts:["हां, लेकिन केवल तभी जब वे सार्वजनिक (public) हों।","हां, बिना किसी प्रतिबंध के।","नहीं, स्थिर मेथड मौलिक रूप से गैर-स्थिर इंस्टेंस चर या विधियों तक सीधे नहीं पहुंच सकते हैं।","केवल मेन मेथड के भीतर।"],ans:2,exp:"स्टेटिक मेथड्स में एक अंतर्निहित (implicit) `this` संदर्भ का अभाव होता है क्योंकि वे किसी विशिष्ट ऑब्जेक्ट इंस्टेंस से बंधे नहीं होते हैं। नतीजतन, एक स्थिर मेथड सीधे गैर-स्थिर क्षेत्रों तक नहीं पहुंच सकता है या उसी क्लास के भीतर गैर-स्थिर विधियों को लागू नहीं कर सकता है जब तक कि यह स्पष्ट रूप से संचालित करने के लिए ऑब्जेक्ट इंस्टेंस नहीं बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What does applying the `final` keyword to a class achieve?",opts:["It marks the class for immediate garbage collection.","It forces the class to contain only abstract methods.","It permanently restricts the class from being extended (inherited by subclasses).","It allows the class to inherit multiple superclasses."],ans:2,exp:"A class decorated with the `final` modifier signals the absolute end of an inheritance tree. The compiler strictly forbids any other class from extending a final class. Java's core `String` class is a primary example; it is declared final to guarantee immutability and security."},hi:{q:"क्लास में `final` कीवर्ड लागू करने से क्या प्राप्त होता है?",opts:["यह तत्काल कचरा संग्रहण के लिए क्लास को चिह्नित करता है।","यह क्लास को केवल अमूर्त (abstract) विधियों को शामिल करने के लिए मजबूर करता है।","यह क्लास को विस्तारित (उपवर्गों द्वारा विरासत में मिलने) होने से स्थायी रूप से प्रतिबंधित करता है।","यह क्लास को कई सुपरक्लासों को इनहेरिट करने की अनुमति देता है।"],ans:2,exp:"`final` मॉडिफायर से सजाया गया क्लास इनहेरिटेंस ट्री के पूर्ण अंत का संकेत देता है। कंपाइलर किसी भी अन्य क्लास को अंतिम (final) क्लास को विस्तारित करने से सख्ती से मना करता है। जावा का कोर `String` क्लास एक प्रमुख उदाहरण है; अपरिवर्तनीयता (immutability) और सुरक्षा की गारंटी के लिए इसे अंतिम (final) घोषित किया गया है।"}},
{type:"mcq",diff:"hard",en:{q:"What defines an 'Abstract Class' in Java?",opts:["It is a class containing only static variables.","It is a strictly restricted class that fundamentally cannot be instantiated on its own.","It represents a class with no methods or fields whatsoever.","It is exactly synonymous with an interface."],ans:1,exp:"An abstract class acts as an incomplete blueprint. Declared using the `abstract` keyword, it absolutely cannot be instantiated using `new`. It usually contains abstract methods (lacking a body) that structurally compel subclasses to provide explicit implementation details."},hi:{q:"जावा में 'एब्सट्रैक्ट क्लास' (Abstract Class) को क्या परिभाषित करता है?",opts:["यह एक क्लास है जिसमें केवल स्थिर (static) चर होते हैं।","यह एक कड़ाई से प्रतिबंधित क्लास है जिसे मौलिक रूप से अपने आप इंस्टेंटियेट (instantiated) नहीं किया जा सकता है।","यह एक ऐसे क्लास का प्रतिनिधित्व करता है जिसमें कोई मेथड या फ़ील्ड नहीं है।","यह एक इंटरफ़ेस के बिल्कुल पर्यायवाची है।"],ans:1,exp:"एक अमूर्त (abstract) क्लास एक अधूरे ब्लूप्रिंट के रूप में कार्य करता है। `abstract` कीवर्ड का उपयोग करके घोषित किया गया है, इसे `new` का उपयोग करके पूरी तरह से त्वरित (instantiated) नहीं किया जा सकता है। इसमें आमतौर पर अमूर्त तरीके (जिनमें कोई बॉडी नहीं होती) शामिल होते हैं जो संरचनात्मक रूप से उपवर्गों को स्पष्ट कार्यान्वयन विवरण प्रदान करने के लिए मजबूर करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which keyword is structurally required for a class to utilize an Interface?",opts:["inherits","includes","implements","extends"],ans:2,exp:"While a class 'extends' another class, it must use the `implements` keyword to commit to an interface. By doing so, the class structurally agrees to provide concrete bodies for all the abstract methods defined within that specific interface, effectively fulfilling a behavioral contract."},hi:{q:"किसी क्लास को इंटरफ़ेस का उपयोग करने के लिए संरचनात्मक रूप से किस कीवर्ड की आवश्यकता होती है?",opts:["inherits","includes","implements","extends"],ans:2,exp:"जबकि एक क्लास दूसरे क्लास को 'extends' करता है, इसे इंटरफ़ेस के प्रति प्रतिबद्ध होने के लिए `implements` कीवर्ड का उपयोग करना चाहिए। ऐसा करने से, क्लास संरचनात्मक रूप से उस विशिष्ट इंटरफ़ेस के भीतर परिभाषित सभी अमूर्त विधियों (abstract methods) के लिए ठोस बॉडी प्रदान करने के लिए सहमत होता है, जो प्रभावी रूप से एक व्यवहार अनुबंध को पूरा करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which block is universally guaranteed to execute regardless of whether an exception is thrown or caught?",opts:["The try block","The catch block","The default block","The finally block"],ans:3,exp:"The `finally` block creates a crucial execution zone appended to a try-catch structure. The JVM guarantees its execution, executing the contained code irrespective of whether a preceding try block succeeds or generates an exception. It is heavily relied upon for mandatory resource cleanup (e.g., closing file streams)."},hi:{q:"यह परवाह किए बिना कि अपवाद (exception) फेंका गया है या पकड़ा गया है, कौन सा ब्लॉक निष्पादित होने की सार्वभौमिक रूप से गारंटी देता है?",opts:["try ब्लॉक","catch ब्लॉक","डिफ़ॉल्ट ब्लॉक","finally ब्लॉक"],ans:3,exp:"`finally` ब्लॉक एक ट्राई-कैच संरचना से जुड़ा एक महत्वपूर्ण निष्पादन क्षेत्र बनाता है। JVM इसके निष्पादन की गारंटी देता है, समाहित कोड को निष्पादित करता है, भले ही पूर्ववर्ती ट्राई ब्लॉक सफल हो या अपवाद उत्पन्न करे। अनिवार्य संसाधन सफाई (जैसे, फ़ाइल स्ट्रीम बंद करना) के लिए इस पर बहुत अधिक भरोसा किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically dictates the functional difference between `throw` and `throws`?",opts:["They are completely identical keywords.","'throws' creates an object, 'throw' prints an error.","`throw` is utilized to explicitly trigger an exception object, whereas `throws` is a method signature declaration indicating exceptions the method might propel.","`throw` is used for classes, `throws` is used for methods."],ans:2,exp:"The `throw` keyword acts instantly within a method's body to deliberately hurl a specific exception object (e.g., `throw new Exception()`). Conversely, `throws` sits passively in the method signature, actively warning the compiler that the method might propagate specific checked exceptions to its caller."},hi:{q:"विशेष रूप से `throw` और `throws` के बीच कार्यात्मक (functional) अंतर क्या तय करता है?",opts:["वे पूरी तरह से समान कीवर्ड हैं।","'throws' एक ऑब्जेक्ट बनाता है, 'throw' एक त्रुटि प्रिंट करता है।","`throw` का उपयोग स्पष्ट रूप से एक अपवाद ऑब्जेक्ट को ट्रिगर करने के लिए किया जाता है, जबकि `throws` एक मेथड सिग्नेचर घोषणा है जो उन अपवादों को इंगित करता है जिन्हें मेथड आगे बढ़ा सकता है।","`throw` का उपयोग क्लासों के लिए किया जाता है, `throws` का उपयोग विधियों के लिए किया जाता है।"],ans:2,exp:"`throw` कीवर्ड जानबूझकर एक विशिष्ट अपवाद ऑब्जेक्ट (जैसे, `throw new Exception()`) को उछालने के लिए एक मेथड के शरीर के भीतर तुरंत कार्य करता है। इसके विपरीत, `throws` मेथड सिग्नेचर में निष्क्रिय रूप से बैठता है, कंपाइलर को सक्रिय रूप से चेतावनी देता है कि मेथड अपने कॉलर को विशिष्ट चेक किए गए अपवादों का प्रचार कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which concept directly underpins Dynamic Method Dispatch (Run-time Polymorphism)?",opts:["Method Overloading","Method Overriding combined with Upcasting","Encapsulation","Static variable assignment"],ans:1,exp:"Dynamic Method Dispatch actively resolves an overridden method call entirely at runtime. It necessitates Upcasting: a parent class reference variable points to a child class object. When an overridden method is invoked, the JVM interrogates the actual object type in memory, not the reference type, to execute the correct method version."},hi:{q:"कौन सी अवधारणा सीधे डायनेमिक मेथड डिस्पैच (रन-टाइम पॉलीमॉर्फिज्म) को रेखांकित करती है?",opts:["मेथड ओवरलोडिंग","अपकास्टिंग (Upcasting) के साथ संयुक्त मेथड ओवरराइडिंग","एनकैप्सुलेशन","स्थिर चर (Static variable) असाइनमेंट"],ans:1,exp:"डायनेमिक मेथड डिस्पैच रनटाइम पर ओवरराइड किए गए मेथड कॉल को सक्रिय रूप से हल करता है। इसके लिए अपकास्टिंग (Upcasting) की आवश्यकता होती है: एक पैरेंट क्लास संदर्भ चर एक चाइल्ड क्लास ऑब्जेक्ट को इंगित करता है। जब किसी ओवरराइड किए गए मेथड को लागू किया जाता है, तो JVM सही मेथड संस्करण को निष्पादित करने के लिए संदर्भ प्रकार को नहीं, बल्कि मेमोरी में वास्तविक ऑब्जेक्ट प्रकार से पूछताछ करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically separates the `==` operator from the `equals()` method when comparing String objects?",opts:["There is absolutely no difference.","`==` compares object references (memory addresses), while `equals()` evaluates the actual textual content inside the objects.","`==` strictly checks case, `equals()` ignores case.","`==` compares strings, `equals()` compares integers."],ans:1,exp:"In Java, the `==` operator assesses object identity, returning true exclusively if both variables reference the exact same memory location on the heap. The `.equals()` method, specifically overridden in the String class, performs a deep logical comparison, evaluating if the sequence of characters is completely identical."},hi:{q:"स्ट्रिंग (String) ऑब्जेक्ट्स की तुलना करते समय विशेष रूप से कौन सा `==` ऑपरेटर को `equals()` मेथड से अलग करता है?",opts:["बिल्कुल कोई अंतर नहीं है।","`==` ऑब्जेक्ट संदर्भों (मेमोरी एड्रेस) की तुलना करता है, जबकि `equals()` ऑब्जेक्ट्स के अंदर वास्तविक टेक्स्ट सामग्री का मूल्यांकन करता है।","`==` सख्ती से केस की जांच करता है, `equals()` केस को नज़रअंदाज़ करता है।","`==` स्ट्रिंग्स की तुलना करता है, `equals()` पूर्णांकों (integers) की तुलना करता है।"],ans:1,exp:"जावा में, `==` ऑपरेटर ऑब्जेक्ट पहचान का आकलन करता है, यह केवल तभी सही (true) लौटाता है जब दोनों चर हीप पर समान मेमोरी स्थान का संदर्भ देते हैं। `.equals()` मेथड, विशेष रूप से स्ट्रिंग क्लास में ओवरराइड किया गया है, एक गहरा तार्किक तुलना करता है, यह मूल्यांकन करता है कि वर्णों का अनुक्रम पूरी तरह से समान है या नहीं।"}},
{type:"mcq",diff:"hard",en:{q:"Where does the JVM store String literals to optimize memory allocation?",opts:["Thread Stack","Method Area","String Constant Pool (intern pool) residing within the Heap space","Registers"],ans:2,exp:"To heavily conserve memory, Java utilizes a dedicated region within the Heap memory dubbed the String Constant Pool. When a new String literal is declared (e.g., `String s = \"Java\"`), the JVM searches the pool; if an identical string already exists, it simply returns that existing reference instead of allocating a new object."},hi:{q:"मेमोरी आवंटन को अनुकूलित (optimize) करने के लिए JVM स्ट्रिंग लिटरल्स (String literals) को कहाँ संग्रहीत करता है?",opts:["थ्रेड स्टैक (Thread Stack)","मेथड एरिया","हीप स्पेस के भीतर स्थित स्ट्रिंग कॉन्स्टेंट पूल (intern pool)","रजिस्टर (Registers)"],ans:2,exp:"मेमोरी के संरक्षण के लिए, जावा हीप (Heap) मेमोरी के भीतर एक समर्पित क्षेत्र का उपयोग करता है जिसे स्ट्रिंग कॉन्स्टेंट पूल कहा जाता है। जब एक नया स्ट्रिंग लिटरल घोषित किया जाता है (जैसे, `String s = \"Java\"`), तो JVM पूल को खोजता है; यदि एक समान स्ट्रिंग पहले से मौजूद है, तो यह एक नया ऑब्जेक्ट आवंटित करने के बजाय उस मौजूदा संदर्भ को वापस कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Why are `StringBuffer` and `StringBuilder` classes specifically preferred over `String` when heavy textual manipulation is required?",opts:["They encrypt strings automatically.","`String` objects are fundamentally immutable (unchangeable), whereas `StringBuffer` and `StringBuilder` dynamically modify the same object without creating excessive garbage objects.","They process strings slower, making them safer.","They can hold integer types inherently."],ans:1,exp:"Because standard String objects are strictly immutable, every modification operation inherently forces the creation of a brand new String object, flooding memory with garbage. `StringBuffer` and `StringBuilder` encapsulate a mutable sequence of characters, heavily optimizing loops or routines that modify textual data repetitively."},hi:{q:"भारी पाठ्य हेरफेर (heavy textual manipulation) की आवश्यकता होने पर `String` के स्थान पर `StringBuffer` और `StringBuilder` क्लासों को विशेष रूप से क्यों पसंद किया जाता है?",opts:["वे स्वचालित रूप से स्ट्रिंग्स को एन्क्रिप्ट करते हैं।","`String` ऑब्जेक्ट मौलिक रूप से अपरिवर्तनीय (अपरिवर्तनीय) होते हैं, जबकि `StringBuffer` और `StringBuilder` अत्यधिक कचरा ऑब्जेक्ट बनाए बिना गतिशील रूप से उसी ऑब्जेक्ट को संशोधित करते हैं।","वे स्ट्रिंग्स को धीमा प्रोसेस करते हैं, जिससे वे सुरक्षित हो जाते हैं।","वे स्वाभाविक रूप से पूर्णांक प्रकार धारण कर सकते हैं।"],ans:1,exp:"चूंकि मानक स्ट्रिंग ऑब्जेक्ट पूरी तरह से अपरिवर्तनीय (immutable) होते हैं, इसलिए प्रत्येक संशोधन ऑपरेशन स्वाभाविक रूप से एक बिल्कुल नए स्ट्रिंग ऑब्जेक्ट के निर्माण को मजबूर करता है, जिससे मेमोरी कचरे से भर जाती है। `StringBuffer` और `StringBuilder` वर्णों के एक परिवर्तनशील अनुक्रम को एनकैप्सुलेट करते हैं, जो उन लूपों या रूटीन को भारी रूप से अनुकूलित करते हैं जो पाठ्य डेटा (textual data) को बार-बार संशोधित करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What precise mathematical value does `Math.random()` typically yield?",opts:["A positive integer between 1 and 100.","A pseudo-random floating-point `double` strictly greater than or equal to 0.0 and strictly less than 1.0.","A random boolean value.","A negative integer."],ans:1,exp:"The `Math.random()` method generates a pseudo-random number generated by the `java.util.Random` class. The returned output is strictly typed as a `double`, encompassing a value space defined precisely as [0.0, 1.0), meaning 0.0 is inclusive but 1.0 is exclusive."},hi:{q:"`Math.random()` आमतौर पर कौन सा सटीक गणितीय मूल्य देता है?",opts:["1 और 100 के बीच एक धनात्मक पूर्णांक (positive integer)।","एक छद्म-यादृच्छिक (pseudo-random) फ़्लोटिंग-पॉइंट `double` जो 0.0 से अधिक या उसके बराबर और 1.0 से कम है।","एक यादृच्छिक (random) बूलियन मान।","एक ऋणात्मक पूर्णांक।"],ans:1,exp:"`Math.random()` मेथड `java.util.Random` क्लास द्वारा उत्पन्न एक छद्म-यादृच्छिक संख्या उत्पन्न करता है। लौटाया गया आउटपुट सख्ती से `double` के रूप में टाइप किया गया है, जिसमें ठीक [0.0, 1.0) के रूप में परिभाषित मूल्य स्थान शामिल है, जिसका अर्थ है 0.0 समावेशी (inclusive) है लेकिन 1.0 अनन्य (exclusive) है।"}},
{type:"mcq",diff:"hard",en:{q:"What evaluates as the precise output of the arithmetic expression `5 / 2` in core Java?",opts:["2.5","2","2.0","Error"],ans:1,exp:"When processing the expression `5 / 2`, both operands are intrinsically of the `int` type. Consequently, the Java compiler executes integer division. Integer division fundamentally discards the fractional remainder, resulting in the truncated integer value `2`. To yield `2.5`, at least one operand must be a double (e.g., `5.0 / 2`)."},hi:{q:"कोर जावा में अंकगणितीय अभिव्यक्ति `5 / 2` का सटीक आउटपुट क्या है?",opts:["2.5","2","2.0","एरर"],ans:1,exp:"अभिव्यक्ति `5 / 2` को संसाधित करते समय, दोनों ऑपरेंड आंतरिक रूप से `int` प्रकार के होते हैं। नतीजतन, जावा कंपाइलर पूर्णांक विभाजन (integer division) निष्पादित करता है। पूर्णांक विभाजन मौलिक रूप से आंशिक शेष (fractional remainder) को छोड़ देता है, जिसके परिणामस्वरूप छंटनी की गई (truncated) पूर्णांक मान `2` प्राप्त होता है। `2.5` प्राप्त करने के लिए, कम से कम एक ऑपरेंड डबल होना चाहिए (उदा., `5.0 / 2`)।"}},
{type:"mcq",diff:"hard",en:{q:"In standard evaluation, what executes as the exact output of `5 % 2`?",opts:["2.5","1","2","0.5"],ans:1,exp:"The `%` (modulo) operator explicitly calculates the mathematical remainder of an integer division operation. When dividing 5 by 2, the primary quotient evaluates to 2 with an exact remainder of 1. Thus, the operator strictly returns the integer `1`."},hi:{q:"मानक मूल्यांकन में, `5 % 2` का सटीक आउटपुट क्या निष्पादित होता है?",opts:["2.5","1","2","0.5"],ans:1,exp:"`%` (मॉड्यूलो) ऑपरेटर स्पष्ट रूप से एक पूर्णांक विभाजन ऑपरेशन के गणितीय शेष (mathematical remainder) की गणना करता है। 5 को 2 से भाग देने पर, प्राथमिक भागफल 1 के सटीक शेष के साथ 2 का मूल्यांकन करता है। इस प्रकार, ऑपरेटर सख्ती से पूर्णांक `1` लौटाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Regarding evaluation mechanics, what differentiates the pre-increment (`++x`) from the post-increment (`x++`) operator?",opts:["They process operations entirely identically.","`++x` immediately increments the variable and evaluates to the new value; `x++` evaluates the expression using the original value, subsequently incrementing it behind the scenes.","`++x` is applicable solely to booleans.","`x++` increments by 2."],ans:1,exp:"The prefix version (`++x`) forcefully increments the variable first, returning the altered value to the ongoing expression. Conversely, the postfix version (`x++`) provides the variable's original, pre-existing value to the expression and defers the incrementing operation until immediately after the evaluation finishes."},hi:{q:"मूल्यांकन यांत्रिकी (evaluation mechanics) के संबंध में, क्या पूर्व-वेतन वृद्धि (pre-increment `++x`) को पोस्ट-इंक्रीमेंट (`x++`) ऑपरेटर से अलग करता है?",opts:["वे संचालन को पूरी तरह से समान रूप से संसाधित करते हैं।","`++x` तुरंत वेरिएबल को बढ़ाता है और नए मान का मूल्यांकन करता है; `x++` मूल मान का उपयोग करके अभिव्यक्ति का मूल्यांकन करता है, बाद में इसे पर्दे के पीछे बढ़ाता है।","`++x` केवल बूलियन पर लागू होता है।","`x++` 2 से बढ़ता है।"],ans:1,exp:"उपसर्ग संस्करण (prefix `++x`) बलपूर्वक पहले वेरिएबल को बढ़ाता है, परिवर्तित मान को चल रही अभिव्यक्ति (expression) में लौटाता है। इसके विपरीत, पोस्टफ़िक्स संस्करण (`x++`) अभिव्यक्ति को चर का मूल, पूर्व-मौजूदा मान प्रदान करता है और मूल्यांकन समाप्त होने के तुरंत बाद वेतन वृद्धि संचालन को टाल देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which specific symbol embodies the Bitwise AND operator in Java's syntax?",opts:["&&","AND","&","||"],ans:2,exp:"The single ampersand `&` strictly performs a bitwise AND calculation. It mathematically compares respective bits of two binary sequences, yielding a 1 exclusively if both corresponding bits are 1. The double ampersand `&&` serves entirely as the logical short-circuiting operator for booleans."},hi:{q:"जावा के सिंटैक्स में बिटवाइज़ एंड (Bitwise AND) ऑपरेटर का प्रतीक कौन सा विशिष्ट चिह्न (symbol) है?",opts:["&&","AND","&","||"],ans:2,exp:"एकल एम्परसेंड `&` कड़ाई से एक बिटवाइज़ AND गणना करता है। यह गणितीय रूप से दो द्विआधारी (binary) अनुक्रमों के संबंधित बिट्स की तुलना करता है, यदि दोनों संबंधित बिट्स 1 हैं, तो विशेष रूप से 1 प्राप्त होता है। डबल एम्परसेंड `&&` पूरी तरह से बूलियन के लिए तार्किक शॉर्ट-सर्किटिंग ऑपरेटर के रूप में कार्य करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically dictates an 'Unchecked Exception' within Java's robust exception handling hierarchy?",opts:["It is heavily verified by the compiler, forcing the programmer to catch it.","It inherits directly from `RuntimeException`, allowing the compiler to entirely bypass checking it during the compilation phase.","It triggers exclusively from syntax errors.","It crashes the physical JVM architecture."],ans:1,exp:"An Unchecked Exception is structurally categorized as any class that extends `RuntimeException`. Due to their unpredictable nature (like `NullPointerException` or arithmetic issues), the compiler fundamentally does not enforce mandatory handling via a try-catch block, shifting responsibility purely to runtime logic."},hi:{q:"जावा के मजबूत अपवाद प्रबंधन पदानुक्रम (exception handling hierarchy) के भीतर विशेष रूप से 'अनचेक अपवाद' (Unchecked Exception) क्या तय करता है?",opts:["कंपाइलर द्वारा इसे भारी रूप से सत्यापित किया जाता है, प्रोग्रामर को इसे पकड़ने के लिए मजबूर किया जाता है।","यह सीधे `RuntimeException` से विरासत में मिलता है, जिससे कंपाइलर को संकलन चरण (compilation phase) के दौरान इसकी जांच को पूरी तरह से बायपास करने की अनुमति मिलती है।","यह विशेष रूप से सिंटैक्स त्रुटियों (syntax errors) से ट्रिगर होता है।","यह भौतिक JVM आर्किटेक्चर को क्रैश करता है।"],ans:1,exp:"एक अनचेक्ड अपवाद (Unchecked Exception) को संरचनात्मक रूप से किसी भी क्लास के रूप में वर्गीकृत किया जाता है जो `RuntimeException` को बढ़ाता है। उनकी अप्रत्याशित प्रकृति (जैसे `NullPointerException` या अंकगणितीय समस्याएँ) के कारण, संकलक (compiler) मौलिक रूप से एक ट्राई-कैच ब्लॉक के माध्यम से अनिवार्य हैंडलिंग को लागू नहीं करता है, जिम्मेदारी को विशुद्ध रूप से रनटाइम लॉजिक में स्थानांतरित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What distinct mechanism occurs if a programmer inadvertently attempts to 'override' a static method in a child class?",opts:["Method Overriding executes perfectly.","Method Hiding occurs; the child method merely overshadows the parent's static method based on reference type rather than participating in dynamic runtime polymorphism.","The Java compiler immediately aborts with an overriding error.","The application executes in an infinite recursive loop."],ans:1,exp:"Because static methods physically bind to their declaring class at compile time rather than an object at runtime, true overriding is impossible. Declaring an identical static method in a subclass structurally triggers 'Method Hiding'. The method invoked relies strictly on the reference variable's class type, ignoring the actual object type completely."},hi:{q:"यदि कोई प्रोग्रामर अनजाने में किसी चाइल्ड क्लास में एक स्थिर (static) मेथड को 'ओवरराइड' करने का प्रयास करता है, तो कौन सा विशिष्ट तंत्र (mechanism) होता है?",opts:["मेथड ओवरराइडिंग पूरी तरह से निष्पादित होता है।","मेथड हाइडिंग (Method Hiding) होता है; चाइल्ड मेथड गतिशील रनटाइम पॉलीमॉर्फिज्म में भाग लेने के बजाय संदर्भ प्रकार (reference type) के आधार पर माता-पिता के स्थिर मेथड को केवल भारी कर देता है।","जावा कंपाइलर तुरंत ओवरराइडिंग त्रुटि के साथ निरस्त हो जाता है।","एप्लिकेशन एक अनंत पुनरावर्ती लूप (infinite recursive loop) में निष्पादित होता है।"],ans:1,exp:"चूंकि स्थिर (static) विधियां रनटाइम पर किसी ऑब्जेक्ट के बजाय संकलन समय (compile time) में अपनी घोषित क्लास से भौतिक रूप से जुड़ती हैं, वास्तविक ओवरराइडिंग असंभव है। उपवर्ग में एक समान स्थिर विधि घोषित करने से संरचनात्मक रूप से 'मेथड हाइडिंग' (Method Hiding) ट्रिगर होता है। लागू की गई विधि (method) वास्तविक वस्तु प्रकार को पूरी तरह से अनदेखा करते हुए, संदर्भ चर के वर्ग प्रकार पर कड़ाई से निर्भर करती है।"}},
{type:"mcq",diff:"hard",en:{q:"In evaluating complex inheritance models, why does Java deliberately reject the implementation of multiple inheritance for classes?",opts:["To simplify loop mechanics.","To decisively eliminate the 'Diamond Problem', where severe ambiguity arises if a subclass inherits highly identical, conflicting method signatures from two disparate superclasses.","To force developers to buy more memory.","To limit class file sizes to exactly 256 bytes."],ans:1,exp:"The prohibition of multiple class inheritance acts as a rigid safeguard against the 'Diamond Problem'. If Class C inherits from Class A and Class B, both housing an identical `doWork()` method, the compiler faces an unresolvable logical collision determining which distinct implementation Class C should logically execute."},hi:{q:"जटिल इनहेरिटेंस मॉडलों का मूल्यांकन करने में, जावा जानबूझकर क्लासों के लिए एकाधिक इनहेरिटेंस (multiple inheritance) के कार्यान्वयन को क्यों अस्वीकार करता है?",opts:["लूप यांत्रिकी (loop mechanics) को सरल बनाने के लिए।","'डायमंड प्रॉब्लम' (Diamond Problem) को निर्णायक रूप से खत्म करने के लिए, जहां गंभीर अस्पष्टता पैदा होती है यदि कोई उपवर्ग दो अलग-अलग सुपरक्लास से अत्यधिक समान, परस्पर विरोधी मेथड हस्ताक्षरों (signatures) को प्राप्त करता है।","डेवलपर्स को अधिक मेमोरी खरीदने के लिए बाध्य करने के लिए।","क्लास फ़ाइल आकार को ठीक 256 बाइट्स तक सीमित करने के लिए।"],ans:1,exp:"मल्टीपल क्लास इनहेरिटेंस का निषेध 'डायमंड प्रॉब्लम' के खिलाफ एक कठोर सुरक्षा के रूप में कार्य करता है। यदि क्लास सी क्लास ए और क्लास बी से इनहेरिट करता है, और दोनों में एक समान `doWork()` मेथड है, तो कंपाइलर को एक अघुलनशील तार्किक टकराव का सामना करना पड़ता है कि यह निर्धारित करने के लिए कि क्लास सी को तार्किक रूप से कौन सा विशिष्ट कार्यान्वयन निष्पादित करना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"How does the `java.util.Scanner` class predominantly differ from primitive input mechanisms?",opts:["It generates viruses.","It actively tokenizes raw input data streams utilizing specific delimiters (whitespace by default), parsing raw strings directly into strongly typed primitives like integers and doubles.","It outputs graphical images to a printer.","It directly edits the Java bytecode compilation."],ans:1,exp:"The `Scanner` class constructs a highly robust text parsing utility. It actively breaks input streams into discrete tokens via predefined delimiter patterns. Crucially, it provides specialized translation methods like `nextInt()` and `nextDouble()` to securely cast text data directly into mathematical primitive types."},hi:{q:"`java.util.Scanner` क्लास मुख्य रूप से आदिम इनपुट तंत्र (primitive input mechanisms) से कैसे भिन्न है?",opts:["यह वायरस उत्पन्न करता है।","यह विशिष्ट सीमांकक (डिफ़ॉल्ट रूप से व्हाइटस्पेस) का उपयोग करके कच्चे इनपुट डेटा स्ट्रीम को सक्रिय रूप से टोकन (tokenize) करता है, कच्चे स्ट्रिंग्स को सीधे पूर्णांक और डबल्स जैसे दृढ़ता से टाइप किए गए आदिम (primitives) में पार्स करता है।","यह एक प्रिंटर को ग्राफिकल चित्र आउटपुट करता है।","यह जावा बाइटकोड संकलन को सीधे संपादित करता है।"],ans:1,exp:"`Scanner` क्लास एक अत्यधिक मजबूत टेक्स्ट पार्सिंग उपयोगिता का निर्माण करता है। यह पूर्वनिर्धारित सीमांकक (delimiter) पैटर्न के माध्यम से इनपुट स्ट्रीम को असतत टोकन में सक्रिय रूप से तोड़ता है। महत्वपूर्ण रूप से, यह टेक्स्ट डेटा को सुरक्षित रूप से सीधे गणितीय आदिम प्रकारों में डालने के लिए `nextInt()` और `nextDouble()` जैसे विशिष्ट अनुवाद विधियाँ प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which exact operator sequence characterizes the Unsigned Right Shift manipulation in Java?",opts:[">>","<<<","=>",">>>"],ans:3,exp:"The `>>>` operator explicitly executes an unsigned right bitwise shift. Regardless of whether the original mathematical value was negative or positive, it forcefully shifts the bits rightward while simultaneously feeding absolute zero `0` bits into the leftmost vacant positions, ignoring standard sign-extension rules."},hi:{q:"कौन सा सटीक ऑपरेटर अनुक्रम जावा में अहस्ताक्षरित राइट शिफ्ट (Unsigned Right Shift) हेरफेर की विशेषता है?",opts:[">>","<<<","=>",">>>"],ans:3,exp:"`>>>` ऑपरेटर स्पष्ट रूप से एक अहस्ताक्षरित दायां (unsigned right) बिटवाइज़ शिफ्ट निष्पादित करता है। इस बात की परवाह किए बिना कि मूल गणितीय मूल्य ऋणात्मक (negative) था या धनात्मक (positive), यह मानक साइन-एक्सटेंशन नियमों को अनदेखा करते हुए, सबसे बाईं ओर खाली पदों में पूर्ण शून्य `0` बिट्स को खिलाने (feeding) के साथ-साथ बिट्स को दाईं ओर बलपूर्वक स्थानांतरित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Within multithreading architectures, what crucial state does the `synchronized` keyword mathematically enforce?",opts:["It allows infinite threads simultaneous entry.","It halts the physical CPU.","It achieves Mutual Exclusion; ensuring that strictly only one thread operates upon a designated block of code or method concurrently, safeguarding shared resources from race conditions.","It immediately destroys threads."],ans:2,exp:"The `synchronized` modifier establishes a fundamental synchronization lock (monitor) mapped to an object. When a thread accesses a synchronized method, it actively monopolizes the lock. Any other threads attempting simultaneous access are forcibly paused, effectively eradicating dangerous concurrent data corruption known as race conditions."},hi:{q:"मल्टीथ्रेडिंग आर्किटेक्चर के भीतर, `synchronized` कीवर्ड किस महत्वपूर्ण स्थिति को गणितीय रूप से लागू करता है?",opts:["यह अनंत थ्रेड्स को एक साथ प्रवेश की अनुमति देता है।","यह भौतिक CPU को रोकता है।","यह पारस्परिक अपवर्जन (Mutual Exclusion) प्राप्त करता है; यह सुनिश्चित करना कि दौड़ की स्थिति (race conditions) से साझा संसाधनों की सुरक्षा करते हुए, केवल एक ही थ्रेड कोड या मेथड के एक निर्दिष्ट ब्लॉक पर समवर्ती रूप से काम करता है।","यह थ्रेड्स को तुरंत नष्ट कर देता है।"],ans:2,exp:"`synchronized` संशोधक (modifier) किसी ऑब्जेक्ट पर मैप किए गए मूलभूत सिंक्रनाइज़ेशन लॉक (मॉनिटर) को स्थापित करता है। जब एक थ्रेड एक सिंक्रनाइज़ मेथड तक पहुंचता है, तो वह सक्रिय रूप से लॉक पर एकाधिकार कर लेता है। एक साथ पहुंच का प्रयास करने वाले किसी भी अन्य थ्रेड को बलपूर्वक रोक दिया जाता है, जो रेस स्थितियों के रूप में ज्ञात खतरनाक समवर्ती डेटा भ्रष्टाचार (concurrent data corruption) को प्रभावी ढंग से समाप्त कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In what specific structural manner does an Interface distinctly differ from an Abstract Class in modern Java?",opts:["Interfaces can hold static methods, abstract classes cannot.","A class can implement multiple interfaces seamlessly, whereas it is strictly confined to extending exactly one singular abstract class.","Abstract classes cannot have methods.","Interfaces can instantiate objects natively using the `new` keyword."],ans:1,exp:"While both constructs mathematically define architectural contracts, Java's architecture absolutely forbids multiple inheritance of abstract classes to avert the Diamond Problem. Conversely, a class can effortlessly implement a mathematically unbounded array of disparate interfaces simultaneously, assembling complex polymorphic behaviors safely."},hi:{q:"आधुनिक जावा में किस विशिष्ट संरचनात्मक तरीके से एक इंटरफ़ेस एक एब्सट्रैक्ट क्लास (Abstract Class) से स्पष्ट रूप से भिन्न होता है?",opts:["इंटरफ़ेस स्थिर (static) तरीके रख सकते हैं, एब्सट्रैक्ट क्लास नहीं कर सकते।","एक क्लास कई इंटरफेस को समेकित (seamlessly) रूप से कार्यान्वित कर सकता है, जबकि यह ठीक एक विलक्षण अमूर्त क्लास के विस्तार (extend) तक सख्ती से सीमित है।","अमूर्त (abstract) क्लासों में तरीके (methods) नहीं हो सकते।","इंटरफेस 'new' कीवर्ड का उपयोग करके ऑब्जेक्ट्स को मूल रूप से इंस्टेंटियेट (instantiate) कर सकते हैं।"],ans:1,exp:"जबकि दोनों रचनाएँ (constructs) गणितीय रूप से वास्तुशिल्प अनुबंधों को परिभाषित करती हैं, जावा का आर्किटेक्चर डायमंड समस्या (Diamond Problem) को टालने के लिए अमूर्त क्लासों के एकाधिक विरासत (multiple inheritance) को पूरी तरह से मना करता है। इसके विपरीत, एक क्लास जटिल बहुरूपी व्यवहारों को सुरक्षित रूप से जोड़ते हुए, एक साथ अलग-अलग इंटरफेस के गणितीय रूप से अनबाउंड ऐरे को आसानी से लागू कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"What characterizes the `java.lang.NullPointerException` heavily utilized in runtime error reporting?",opts:["It alerts the user that the RAM is fully consumed.","It strictly triggers when application logic inadvertently attempts to execute a method or manipulate a property on an object reference that currently points to the void `null` state.","It indicates a missing semicolon in the syntax.","It occurs strictly during mathematical division by zero."],ans:1,exp:"A `NullPointerException` (NPE) represents a catastrophic runtime anomaly. It triggers instantaneously when code logic forcefully interacts with an object reference variable that lacks a concrete memory allocation (meaning it strictly points to `null`). Operations like querying `.length()` on a null array invoke this failure."},hi:{q:"रनटाइम त्रुटि रिपोर्टिंग में भारी मात्रा में उपयोग किए जाने वाले `java.lang.NullPointerException` की क्या विशेषता है?",opts:["यह उपयोगकर्ता को सचेत करता है कि RAM पूरी तरह से उपभोग कर ली गई है।","यह सख्ती से तब ट्रिगर होता है जब एप्लिकेशन लॉजिक अनजाने में किसी मेथड को निष्पादित करने का प्रयास करता है या ऑब्जेक्ट संदर्भ पर किसी संपत्ति में हेरफेर करता है जो वर्तमान में शून्य `null` स्थिति को इंगित करता है।","यह सिंटैक्स में एक लापता अर्धविराम (semicolon) को इंगित करता है।","यह सख्ती से शून्य से गणितीय विभाजन के दौरान होता है।"],ans:1,exp:"`NullPointerException` (NPE) एक विनाशकारी रनटाइम विसंगति का प्रतिनिधित्व करता है। यह तुरंत ट्रिगर होता है जब कोड लॉजिक बलपूर्वक किसी ऑब्जेक्ट रेफरेंस वेरिएबल के साथ इंटरैक्ट करता है जिसमें ठोस मेमोरी एलोकेशन का अभाव होता है (जिसका अर्थ है कि यह कड़ाई से `null` को इंगित करता है)। एक शून्य (null) ऐरे पर `.length()` की पूछताछ जैसे संचालन इस विफलता का आह्वान करते हैं।"}},
{type:"tf",diff:"hard",en:{q:"In standard Java architecture, the `main` method fundamentally cannot be subjected to Method Overloading logic under any circumstances.",opts:["True","False"],ans:1,exp:"False. The `main` method can be flawlessly overloaded just like any standard Java method. However, the JVM is strictly programmed to locate and trigger only the specific signature `public static void main(String[] args)` to initiate program execution. Secondary overloaded `main` methods must be called manually."},hi:{q:"मानक जावा आर्किटेक्चर में, `main` मेथड मौलिक रूप से किसी भी परिस्थिति में मेथड ओवरलोडिंग लॉजिक के अधीन नहीं हो सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। `main` मेथड को किसी भी मानक जावा मेथड की तरह त्रुटिहीन रूप से ओवरलोड किया जा सकता है। हालाँकि, JVM को कड़ाई से प्रोग्राम निष्पादन शुरू करने के लिए केवल विशिष्ट सिग्नेचर `public static void main(String[] args)` का पता लगाने और ट्रिगर करने के लिए प्रोग्राम किया गया है। माध्यमिक ओवरलोडेड `main` मेथड्स को मैन्युअल रूप से बुलाया जाना चाहिए।"}},
{type:"tf",diff:"hard",en:{q:"To deeply enforce Data Encapsulation, all class variables must invariably be declared using the `public` access modifier.",opts:["True","False"],ans:1,exp:"False. Data Encapsulation strictly dictates exactly the opposite approach. To aggressively shield the internal state of an object from erratic external interference, class variables are heavily advised to be declared `private`. Controlled external access is then systematically granted exclusively via public getter and setter methods."},hi:{q:"डेटा एनकैप्सुलेशन को गहराई से लागू करने के लिए, सभी क्लास वेरिएबल्स को हमेशा `public` एक्सेस मॉडिफायर का उपयोग करके घोषित किया जाना चाहिए।",opts:["सही","गलत"],ans:1,exp:"गलत। डेटा एनकैप्सुलेशन कड़ाई से बिल्कुल विपरीत दृष्टिकोण तय करता है। किसी वस्तु की आंतरिक स्थिति को अनिश्चित बाहरी हस्तक्षेप से आक्रामक रूप से बचाने के लिए, क्लास वेरिएबल्स को 'निजी' (`private`) घोषित करने की भारी सलाह दी जाती है। फिर नियंत्रित बाहरी पहुंच को व्यवस्थित रूप से विशेष रूप से सार्वजनिक गेट्टर (getter) और सेटर (setter) मेथड्स के माध्यम से प्रदान किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What happens in Java memory when you reassign a new value to an existing `String` variable (e.g., `str = \"NewValue\"`)?",opts:["The original string object is modified in place to hold the new value.","A completely new String object is created in memory, and the reference is updated to point to it.","The JVM throws a runtime error because Strings cannot be reassigned.","The variable type automatically changes to StringBuilder."],ans:1,exp:"In Java, `String` objects are fundamentally immutable, meaning their state cannot be changed after creation. When you reassign a new value to an existing `String` reference, the JVM does not overwrite the old object. Instead, it dynamically allocates memory for a brand new `String` object (either in the String Pool or on the heap) and updates the reference variable to point to this newly created object, leaving the old object for Garbage Collection if unreferenced."},hi:{q:"जब आप जावा में किसी मौजूदा `String` वेरिएबल को एक नया मान निर्दिष्ट (reassign) करते हैं (उदा., `str = \"NewValue\"`), तो मेमोरी में क्या होता है?",opts:["मूल स्ट्रिंग ऑब्जेक्ट को नए मान को रखने के लिए उसी स्थान पर संशोधित किया जाता है।","मेमोरी में एक पूरी तरह से नया स्ट्रिंग ऑब्जेक्ट बनाया जाता है, और संदर्भ (reference) को इसे इंगित करने के लिए अद्यतन किया जाता है।","JVM एक रनटाइम त्रुटि फेंकता है क्योंकि स्ट्रिंग्स को फिर से असाइन नहीं किया जा सकता है।","वेरिएबल प्रकार स्वचालित रूप से StringBuilder में बदल जाता है।"],ans:1,exp:"जावा में, `String` ऑब्जेक्ट मौलिक रूप से अपरिवर्तनीय (immutable) होते हैं, जिसका अर्थ है कि निर्माण के बाद उनकी स्थिति को बदला नहीं जा सकता है। जब आप एक मौजूदा `String` संदर्भ में एक नया मान असाइन करते हैं, तो JVM पुराने ऑब्जेक्ट को अधिलेखित (overwrite) नहीं करता है। इसके बजाय, यह एक बिल्कुल नए स्ट्रिंग ऑब्जेक्ट के लिए गतिशील रूप से मेमोरी आवंटित करता है और इस नए बनाए गए ऑब्जेक्ट को इंगित करने के लिए संदर्भ चर को अपडेट करता है, पुराने ऑब्जेक्ट को कचरा संग्रहण (Garbage Collection) के लिए छोड़ देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a Java multithreading environment, what is the critical architectural difference between the `Thread.sleep()` and `Object.wait()` methods regarding monitor locks?",opts:["`Thread.sleep()` releases the monitor lock, whereas `Object.wait()` retains the lock indefinitely.","`Thread.sleep()` retains the acquired monitor lock while paused, whereas `Object.wait()` explicitly releases the lock, allowing other threads to access the synchronized block.","Both methods release the lock, but `wait()` requires a specified timeout parameter.","Both methods retain the lock, but `sleep()` can only be called from inside a `synchronized` block."],ans:1,exp:"The distinction lies in monitor lock handling. `Thread.sleep()` is a static method that suspends the current thread's execution for a specified duration but stringently holds onto any synchronized monitor locks it has acquired. Conversely, `Object.wait()` is an instance method called within a synchronized context that intentionally releases the monitor lock, forcing the thread into a waiting state until another thread invokes `notify()` or `notifyAll()` on the exact same object."},hi:{q:"जावा मल्टीथ्रेडिंग वातावरण में, मॉनिटर लॉक के संबंध में `Thread.sleep()` और `Object.wait()` विधियों (methods) के बीच महत्वपूर्ण वास्तुशिल्प अंतर क्या है?",opts:["`Thread.sleep()` मॉनिटर लॉक जारी करता है, जबकि `Object.wait()` लॉक को अनिश्चित काल तक बनाए रखता है।","`Thread.sleep()` रुके रहने के दौरान प्राप्त मॉनिटर लॉक को बनाए रखता है, जबकि `Object.wait()` स्पष्ट रूप से लॉक जारी करता है, जिससे अन्य थ्रेड्स को सिंक्रनाइज़ ब्लॉक तक पहुंचने की अनुमति मिलती है।","दोनों विधियाँ लॉक जारी करती हैं, लेकिन `wait()` को एक निर्दिष्ट टाइमआउट पैरामीटर की आवश्यकता होती है।","दोनों विधियाँ लॉक को बनाए रखती हैं, लेकिन `sleep()` को केवल `synchronized` ब्लॉक के अंदर से कॉल किया जा सकता है।"],ans:1,exp:"यह अंतर मॉनिटर लॉक हैंडलिंग में निहित है। `Thread.sleep()` एक स्थिर (static) विधि है जो वर्तमान थ्रेड के निष्पादन को एक निर्दिष्ट अवधि के लिए निलंबित कर देती है, लेकिन इसके द्वारा प्राप्त किसी भी सिंक्रनाइज़ मॉनिटर लॉक को कड़ाई से पकड़े रहती है। इसके विपरीत, `Object.wait()` एक सिंक्रनाइज़ संदर्भ के भीतर बुलाया जाने वाला एक इंस्टेंस मेथड है जो जानबूझकर मॉनिटर लॉक को जारी (release) करता है, थ्रेड को प्रतीक्षा स्थिति में मजबूर करता है जब तक कि कोई अन्य थ्रेड उसी ऑब्जेक्ट पर `notify()` या `notifyAll()` लागू नहीं करता।"}}
];

